VISUAL_PROMPT_CONTAMINATION_RE = re.compile(
    r"(?:^|\s)(?:提示词|绘图提示词|图片提示词|Prompt|Image Prompt)\s*[：:]|"
    r"Generate\s+an\s+image|--ar\s*\d+\s*:\s*\d+|"
    r"CONTENT PAGE SOFTWARE LOGO LOCK|GLOBAL IMAGE RULES|Fixed global spec|"
    r"software(?:—|-)?not the image model|software post-processing|"
    r"Helvetica Neue|Source Han Sans SC|#1F3A5F|opacity\s*0\.90|"
    r"do not render any brand text|reserve a clean empty top-left area|"
    r"SCIENTIFICALLY ACCURATE AND SOURCE-GROUNDED MEDICAL TEXTBOOK FIGURE|Generate an image showing|after generation the program will stamp",
    re.I,
)


def is_visual_prompt_contamination(text: str) -> bool:
    """判断某行是否属于绘图提示词/视觉硬约束，避免混入台词文件和 LRC。"""
    t = str(text or "").strip()
    if not t:
        return False
    return bool(VISUAL_PROMPT_CONTAMINATION_RE.search(t))


def purge_visual_prompt_contamination_from_voiceover(text: str) -> str:
    """从台词文本中清除误混入的绘图提示词行；只做删除，不改写口播正文。"""
    kept = []
    for raw in str(text or "").splitlines():
        line = raw.strip()
        if not line:
            continue
        line = _strip_after_any_prompt_marker(line).strip()
        if not line or is_visual_prompt_contamination(line):
            continue
        kept.append(line)
    return "\n".join(kept).strip() + ("\n" if kept else "")



