def _is_separator_line(line: str) -> bool:
    t = str(line or "").strip()
    return bool(t) and bool(re.fullmatch(r"[=\-—_\s]{3,}", t))


def _normalize_header_line(line: str) -> str:
    t = str(line or "").strip()
    t = re.sub(r"^[#\s>*`\-•]+", "", t)
    t = re.sub(r"[*_`]+", "", t)
    t = t.strip("【】[]()（） ")
    t = re.sub(r"\s+", "", t)
    return t


def _is_voiceover_section_header(line: str) -> bool:
    t = _normalize_header_line(line)
    if not t:
        return False
    tl = t.lower()
    return (
        "纯台词脚本" in t
        or "纯台词" in t
        or ("第一部分" in t and ("台词" in t or "口播" in t or "旁白" in t))
        or ("partone" in tl and ("voiceover" in tl or "script" in tl))
        or "purevoiceoverscript" in tl
        or re.fullmatch(r"(?:台词|口播|旁白|解说词)(?:脚本|文案|台词)?", t) is not None
    )


def _is_drawing_section_header(line: str) -> bool:
    t = _normalize_header_line(line)
    if not t:
        return False
    tl = t.lower()
    return (
        "独立绘图提示词" in t
        or "绘图提示词" in t

        or "绘图脚本" in t
        or ("第二部分" in t and ("绘图" in t or "提示词" in t or "分镜" in t))
        or ("parttwo" in tl and ("image" in tl or "prompt" in tl or "storyboard" in tl or "productionassetplan" in tl or "assetplan" in tl))
        or "independentimageprompts" in tl
        or re.fullmatch(r"(?:分镜)?(?:绘图|图片|配图)(?:提示词|脚本)", t) is not None
    )


def split_raw_script_sections(raw_script_text: str):
    """从完整脚本原稿中按明确章节标题强制拆分。

    兼容以下输出：
    - 【第一部分：纯台词脚本】 / 【第二部分：独立绘图提示词】
    - 【纯台词脚本】 / 【独立绘图提示词】
    - 纯台词 / 绘图提示词
    如果没有明确标题，返回两个空字符串，交给旧解析器兜底。

    """
    voice_lines, drawing_lines = [], []
    mode = None
    seen_voice_header = False
    seen_drawing_header = False
    for raw in str(raw_script_text or "").replace("\r\n", "\n").replace("\r", "\n").splitlines():
        line = raw.rstrip()
        if _is_separator_line(line):
            continue
        if _is_voiceover_section_header(line):
            mode = "voiceover"
            seen_voice_header = True
            continue
        if _is_drawing_section_header(line):
            mode = "drawing"
            seen_drawing_header = True
            continue
        if mode == "voiceover":
            voice_lines.append(line)
        elif mode == "drawing":
            drawing_lines.append(line)
    voice = "\n".join(voice_lines).strip()
    drawing = "\n".join(drawing_lines).strip()
    if seen_voice_header or seen_drawing_header:
        return voice, drawing
    return "", ""


def clean_voiceover_section_text(section_text: str) -> str:
    """清洗明确“纯台词脚本”区块，保留台词，不引入绘图提示词。"""
    kept = []
    for raw in str(section_text or "").splitlines():
        line = raw.strip()
        if not line or _is_separator_line(line):
            continue
        if _is_drawing_section_header(line) or LRC_STOP_FIELD_RE.match(line) or LRC_BLOCK_HEADER_RE.match(line) or re.search(r"(?i)Part\s*Two\s*:\s*Production\s*Asset\s*Plan|Production\s*Asset\s*Plan|AI\s*Image\s*Layer|Page\s*Type\s*:", line):
            break
        cleaned = clean_voiceover_line(line)
        if cleaned:
            kept.extend(split_voiceover_preserve_sentences(cleaned))
    return "\n".join([x.strip() for x in kept if x.strip()]).strip() + ("\n" if kept else "")


def clean_drawing_section_text(section_text: str) -> str:
    """清洗明确“绘图提示词”区块，只去掉围栏和分隔线，不压缩、不重写。"""
    lines = []
    for raw in str(section_text or "").replace("\r\n", "\n").replace("\r", "\n").splitlines():
        line = raw.rstrip()
        if _is_separator_line(line):
            continue
        if line.strip().startswith("```"):
            continue
        lines.append(line)
    text = "\n".join(lines).strip()
    return text + ("\n" if text else "")


def clean_voiceover_line(line: str) -> str:
    """清理单行口播台词：去字段名、项目符号、多余空白，并截断误混入的提示词。"""
    t = str(line or "").strip()
    if not t:
        return ""
    t = _strip_after_any_prompt_marker(t)
    if not t or is_visual_prompt_contamination(t):
        return ""
    t = re.sub(r"^\s*[-•*]+\s*", "", t)
    t = re.sub(r"^\s*(?:口播文案|口播台词|口语台词|旁白|解说词|voiceover)\s*[：:]\s*", "", t, flags=re.I)
    t = re.sub(r"^【口播(?:文案|台词)?】\s*", "", t)
    t = _strip_after_any_prompt_marker(t)
    t = re.sub(r"\s+", " ", t).strip()
    if is_visual_prompt_contamination(t):
        return ""
    return t


def build_voiceover_transcript_text(script_text: str) -> str:
    """从完整脚本原稿中提取纯台词。

    优先使用“【纯台词脚本】/【独立绘图提示词】”这类双区块拆分；
    若模型没有按双区块输出，再退回旧的口播字段提取。
    """
    voice_section, _ = split_raw_script_sections(script_text or "")
    if voice_section.strip():
        cleaned = clean_voiceover_section_text(voice_section)
        if cleaned.strip():
            return cleaned
    sentences = extract_voiceover_sentences(script_text or "")
    if not sentences:
        # 最后兜底：如果没有绘图区块，就把非视觉污染行当作台词候选。
        _, drawing_section = split_raw_script_sections(script_text or "")
        if not drawing_section.strip():
            sentences = extract_plain_voiceover_lines(script_text or "")
    return "\n".join([str(s).strip() for s in sentences if str(s).strip()]) + ("\n" if sentences else "")



_PAGE_TYPE_BODY_FOLLOW_MARKER_RE = r"(?:AI\s+Image\s+Layer\s+Prompt|AI\s+Prompt|Prompt|提示词|VOICEOVER-DRIVEN|PAIRED\s+VOICEOVER|Biomedical\s+visual\s+subject|Semantic\s+relationship|Composition|Style|GLOBAL\s+SCRIPT\s+THEME|A-SERIES|C-PAGE)"


def _split_leading_page_type_and_body(text: str) -> tuple[str, str]:
    """把开头 Page Type 与后续真正提示词正文拆开。

    关键兼容：部分流程会把换行压成空格，形成
    "Page Type: B. Main Content Page AI Image Layer Prompt: ..."。
    旧版按整行替换 Page Type 时会把 AI Image Layer Prompt 正文一并吞掉。
    """
    raw = str(text or "").strip()
    if not raw:
        return "", ""
    m = re.match(
        rf"(?is)^\s*Page\s*Type\s*[：:]\s*(.*?)\s*(?=(?:\n|\s+{_PAGE_TYPE_BODY_FOLLOW_MARKER_RE}\b|$))",
        raw,
    )
    if not m:
        return "", raw
    page_type = (m.group(1) or "").strip()
    body = raw[m.end():].strip()
    return page_type, body


def _normalize_prompt_page_type_newline(prompt: str) -> str:
    """确保 Page Type 独占一行，防止后续正则整行替换误删正文。"""
    page_type, body = _split_leading_page_type_and_body(prompt)
    if not page_type:
        return str(prompt or "").strip()
    return (f"Page Type: {page_type}\n{body}" if body else f"Page Type: {page_type}").strip()

def _saved_prompt_max_chars_for_name(name: str, prompt: str = "") -> int:
    """v8.2：默认不限制落盘绘图提示词长度；保留函数名兼容旧调用。"""
    try:
        return int(IMAGE_PROMPT_SOURCE_MAX_CHARS or 0)
    except Exception:
        return 0


def _limit_saved_image_prompt_text(prompt: str, name: str = "") -> str:
    """落盘前只规范 Page Type 换行和空白，不再截断提示词。

    旧版为了省 token 会截断 B/A/C 提示词，导致最终文件出现 `restrained ac...`
    一类半截英文。这里禁止机械截断；如果提示词太长，应在生成规则中重写得更短，
    不能在保存阶段截掉正文。
    """
    raw = str(prompt or "").strip()
    if not raw:
        return ""
    page_type, body = _split_leading_page_type_and_body(raw)
    if page_type:
        body = re.sub(r"\s+", " ", body).strip()
        return (f"Page Type: {page_type}\n{body}" if body else f"Page Type: {page_type}").strip()
    return re.sub(r"\s+", " ", raw).strip()



def compact_voiceover_text_preserving_all(voiceover_text: str) -> str:
    """不删关键信息，只做最小化整理：去字段名、压缩空行、保留一行一句，并清除误混入的提示词。"""
    lines = []
    for raw_line in str(voiceover_text or "").splitlines():
        line = clean_voiceover_line(raw_line)
        if line:
            lines.append(line)
    return purge_visual_prompt_contamination_from_voiceover("\n".join(lines))


def build_image_prompt_file_text(script_text: str, logger=None) -> str:
    """从完整脚本原稿中提取独立绘图脚本/绘图提示词文件。

    优先原样保存“【独立绘图提示词】”区块，不压缩、不重写、不追加规格；
    若模型没有输出明确区块，再用旧解析器按 Prompt/提示词 字段兜底提取。
    """
    # v123：如果完整原稿是 Production Asset Plan，优先只保存 AI Image Layer 的 Prompt，避免把后处理坐标/文字交给图像模型。
    layered_prompts = ScriptParser.extract_image_prompts(script_text or "", logger=logger)
    if layered_prompts and re.search(r"(?i)Production\s+Asset\s+Plan|AI\s+Image\s+Layer", str(script_text or "")):
        blocks = []
        for name, prompt in layered_prompts:
            prompt = _limit_saved_image_prompt_text(prompt, name=name)
            blocks.append(f"**{name}")
            blocks[-1] = blocks[-1] + "**"
            blocks.append(f"提示词：{prompt}")
            blocks.append("")
        return "\n".join(blocks).rstrip() + "\n"

    _, drawing_section = split_raw_script_sections(script_text or "")
    if drawing_section.strip():
        raw = clean_drawing_section_text(drawing_section)
        if raw.strip():
            return raw
    prompts = ScriptParser.extract_image_prompts(script_text or "", logger=None)
    if not prompts:
        return ""
    blocks = []
    for idx, (name, prompt) in enumerate(prompts, 1):
        label = name.replace("_", " ")
        if not re.match(r"^(镜头|推文图)\s*\d+", label, flags=re.I):
            label = f"镜头 {idx:02d}"
        prompt_text = _limit_saved_image_prompt_text(str(prompt or "").strip(), name=label)
        blocks.append(f"**{label}**")
        blocks.append(f"提示词：{prompt_text}")
        blocks.append("")
    return "\n".join(blocks).rstrip() + "\n"




def get_voice_image_alignment_script_path(script_path: str) -> str:
    """保存“绘图提示词 + 台词一一对应脚本”，作为拆分前的稳定中间稿。"""
    base, _ = os.path.splitext(script_path)
    return base + "_08_图文对齐脚本_审阅版.txt"


def get_voice_image_master_script_path(script_path: str) -> str:
    """保存图文一一对应总脚本；供后续拆分台词、重建 LRC 和断点续跑统一读取。

    v123 引入分层 Production Asset Plan 后，主流程会先生成图文对应中间稿，
    但旧补丁遗漏了这个路径函数，导致运行时报 NameError。这里恢复稳定入口。
    """
    base, _ = os.path.splitext(script_path)
    return base + "_09_图文对齐总脚本_拆分依据.txt"


def split_raw_script_to_voiceover_and_prompts_no_lrc_markers(raw_script_text: str, logger=None):
    """只从完整原稿剥离纯台词和绘图提示词，不写入【图N】。图号必须由图文对应步骤生成。"""
    voiceover_text = build_voiceover_transcript_text(raw_script_text)
    image_prompt_text = build_image_prompt_file_text(raw_script_text, logger=logger)
    return voiceover_text, image_prompt_text


def _prompt_excerpt_for_alignment(prompt: str, max_chars: int = 900) -> str:
    """给图文对应模型看的提示词摘要；最终绘图提示词仍使用原文，不使用摘要。"""
    t = re.sub(r"\s+", " ", str(prompt or "")).strip()
    if len(t) <= max_chars:
        return t
    return t[:max_chars].rstrip() + " ..."


def infer_alignment_page_type(prompt_name: str, prompt_text: str, image_no: int = 0, total: int = 0) -> str:
    """给图文对应中间稿标注页型，便于人工检查；不改写绘图提示词。"""
    name = str(prompt_name or "")
    prompt = str(prompt_text or "")
    joined = name + "\n" + prompt
    m = re.search(r"(?im)^\s*Page\s*Type\s*[：:]\s*([^\n]+)\s*$", joined)
    if m:
        page = re.sub(r"\s+", " ", m.group(1).strip())
        # 模型偶尔把 A01/A02 派生页标成 B；文件名/提示词槽位优先。
        if re.search(r"(?:^|[^A-Z0-9])A01(?:[^A-Z0-9]|$)|Bilibili\s*Cover|B站封面", joined, flags=re.I):
            return "A01. Bilibili Cover Page"
        if re.search(r"(?:^|[^A-Z0-9])A02(?:[^A-Z0-9]|$)|Bilibili\s*Home|B站首页", joined, flags=re.I):
            return "A02. Bilibili Home Page"
        return page
    if re.search(r"(?:^|[^A-Z0-9])A01(?:[^A-Z0-9]|$)|Bilibili\s*Cover|B站封面", joined, flags=re.I):
        return "A01. Bilibili Cover Page"
    if re.search(r"(?:^|[^A-Z0-9])A02(?:[^A-Z0-9]|$)|Bilibili\s*Home|B站首页", joined, flags=re.I):
        return "A02. Bilibili Home Page"
    if re.search(r"(?:\bA2\b|Home\s*Page|首页)", joined, flags=re.I) or int(image_no or 0) == 2:
        return "A2. Home Page"
    if re.search(r"(?:\bA1\b|Video\s*Cover|封面)", joined, flags=re.I) or int(image_no or 0) == 1:
        return "A1. Video Cover Page"
    if re.search(r"(?:Final\s*Shot|Brand\s*Page|C\.\s*Brand|品牌页|结尾|尾页)", joined, flags=re.I) or (total and int(image_no or 0) == int(total)):
        return "C. Brand Page"
    return "B. Main Content Page"

def ordered_voiceover_sentences_for_alignment(voiceover_text: str) -> list:
    """把纯台词整理成按原顺序排列的句子，供硬性页型映射使用。"""
    sentences = []
    for raw in str(voiceover_text or "").splitlines():
        cleaned = clean_voiceover_line(raw)
        if cleaned:
            sentences.extend(split_voiceover_preserve_sentences(cleaned))
    return [strip_lrc_image_markers(s).strip() for s in sentences if strip_lrc_image_markers(s).strip()]


def find_a2_chapter_overview_sentence(voiceover_text: str):
    """查找必须绑定到 A2 Home Page 的章节提要句。

    优先匹配用户指定的结构：
    “在《书名》第X章中，我们将讨论……：……”
    返回 (句子, 1-based序号)，未找到则返回 ("", 0)。
    """
    sentences = ordered_voiceover_sentences_for_alignment(voiceover_text)
    if not sentences:
        return "", 0
    preferred_patterns = [
        r"^在《[^》]+》第[一二三四五六七八九十百千万0-9]+章中[，,]?我们将讨论",
        r"^在《[^》]+》[^。！？!?]*第[一二三四五六七八九十百千万0-9]+章[^。！？!?]*(?:我们将|本章将|这一章将)[^。！？!?]*(?:讨论|讲解|梳理|聚焦|介绍)",
        r"^今天[^。！？!?]*《[^》]+》[^。！？!?]*第[一二三四五六七八九十百千万0-9]+章[^。！？!?]*(?:讨论|讲解|梳理|聚焦|介绍)",
    ]
    for pat in preferred_patterns:
        for idx, sent in enumerate(sentences, 1):
            comparable = re.sub(r"^\s*\d{1,3}\s*[.．、]\s*", "", sent).strip()
            if re.search(pat, comparable):
                return sent, idx
    # 兜底：含书名、章节号和“我们将讨论”的句子，一般就是章节提要。
    for idx, sent in enumerate(sentences, 1):
        comparable = re.sub(r"^\s*\d{1,3}\s*[.．、]\s*", "", sent).strip()
        if "《" in comparable and "》" in comparable and "章" in comparable and "我们将讨论" in comparable:
            return sent, idx
    return "", 0


def remove_sentence_from_alignment_value(value: str, target_sentence: str) -> str:
    """从某个图号的台词段里移除指定句，避免 A2 章节提要重复出现在别的页。"""
    target_norm = normalize_text_for_marker_match(target_sentence)
    kept = []
    for raw in str(value or "").splitlines():
        line = clean_voiceover_line(raw)
        if not line:
            continue
        for sent in split_voiceover_preserve_sentences(line):
            sent_clean = strip_lrc_image_markers(sent)
            norm = normalize_text_for_marker_match(sent_clean)
            if target_norm and norm and (norm == target_norm or norm in target_norm or target_norm in norm):
                continue
            if sent_clean:
                kept.append(sent_clean)
    return "\n".join(kept).strip()


def enforce_a2_chapter_overview_alignment(mapping: dict, voiceover_text: str, total_images: int = 0, logger=None) -> dict:
    """硬性修正图文对应：A2 Home Page/图2 必须绑定章节提要句，而不是普通封面或内容图。"""
    if not mapping:
        return mapping
    try:
        total_images = int(total_images or 0)
    except Exception:
        total_images = 0
    if total_images and total_images < 2:
        return mapping
    overview_sentence, overview_idx = find_a2_chapter_overview_sentence(voiceover_text)
    if not overview_sentence:
        if logger:
            logger("⚠️ 未找到可绑定 A2 Home Page 的章节提要句；请检查开头是否包含“在《书名》第X章中，我们将讨论……”结构。")
        return mapping

    fixed = dict(mapping)
    for k in list(fixed.keys()):
        fixed[k] = remove_sentence_from_alignment_value(fixed.get(k, ""), overview_sentence)

    # A2 只绑定章节提要句，保证 LRC 中【图2】的第一句就是“003. 章节提要”对应内容。
    fixed[2] = overview_sentence

    # 若章节提要前有开场句，优先确保 A1 承接这些开场句。
    all_sentences = ordered_voiceover_sentences_for_alignment(voiceover_text)
    if overview_idx > 1:
        before = [s for s in all_sentences[:overview_idx - 1] if normalize_text_for_marker_match(s) != normalize_text_for_marker_match(overview_sentence)]
        if before:
            existing_1 = str(fixed.get(1, "")).strip()
            if not existing_1:
                fixed[1] = "\n".join(before).strip()

    if logger:
        logger(f"🔒 已硬性绑定 A2 Home Page / 图2 到第 {overview_idx:03d} 句章节提要：{overview_sentence[:80]}")
    return fixed


def build_voice_image_alignment_prompt(voiceover_text: str, image_prompt_text: str, *, max_chars: int = 60000) -> str:
    """让文本模型只做台词到图号的映射；不改写绘图提示词，不生成新画面。"""
    voice = str(voiceover_text or "").strip()
    prompts = ScriptParser.extract_image_prompts(image_prompt_text or "", logger=None)
    if not voice or not prompts:
        return ""
    prompt_lines = []
    for i, (name, ptxt) in enumerate(prompts, 1):
        page_type = infer_alignment_page_type(name, ptxt, i, len(prompts))
        label = lrc_image_label_for_index(i, total_images=len(prompts), page_type=page_type, prompt_name=name)
        excerpt = _prompt_excerpt_for_alignment(ptxt, max_chars=420)
        prompt_lines.append(f"{label}: {name} | {page_type} | {excerpt}")
    body = (
        "请把中文旁白按顺序分配到对应配图编号，用于生成 LRC 配图锚点。LRC 只写最终时间戳，不用于切画面。\n"
        "核心目标：每个非封面编号对应 3~8 秒可朗读台词，且台词必须能直接解释该图的医学视觉主体、机制、证据、对比或问题。\n"
        "大模型/Gemini 必须按镜头密度执行：超过 8 秒必须拆分，不足 3 秒且语义未变才可合并；不得把长段台词塞进一张 B 图。\n"
        "在保持原文先后顺序的前提下，按 3~8 秒镜头和语义相关性分配连续台词段；不要机械平均分配，不要把泛泛过渡句错配给具体机制图。\n"
        "B 图要优先匹配同一核心概念：例如受体配受体图、突触配突触图、神经环路配神经环路图、记忆/学习机制配对应机制图；每张 B 图后处理只允许叠加简短英文关键词图注，不允许中文字符。\n"
        "术语必须按神经科学专业中文审校：neural circuit 译为“神经环路”，不要写“神经回路”或“神经电路”。\n"
        "只输出映射，不要改写台词，不要新增事实，不要输出解释。\n"
        "输出格式必须逐项使用：A1：<无对应台词或开场过渡台词>\nA2：<对应台词>\nB01：<3~8秒对应台词>\nB02：<3~8秒对应台词>\n...\nC：<对应台词>\n"
        "A1 是封面页，不生成 LRC 台词锚点；A2 对应章节提要句；B 图对应中段机制/证据/步骤；C 对应结尾总结或关注语。\n\n"
        "【旁白原文】\n" + voice[:max_chars//2] + "\n\n"
        "【图片列表】\n" + "\n".join(prompt_lines)[:max_chars//2]
    )
    return body.strip()


ALIGNMENT_MAP_HEADER_RE = re.compile(
    r"(?im)^\s*(?:[-*]\s*)?(?:【\s*)?(?:(?:图|Image|Shot)\s*[_\- ]*0*(\d+)|(A1|A2|A01|A02|B\d{1,3}|C))\s*(?:】)?\s*(?:对应台词|台词|voiceover)?\s*[：:]\s*(.*)$"
)


def parse_voice_image_alignment_map(alignment_text: str, total_images: int = 0) -> dict:
    """解析模型输出的“A2/B01/C 或旧图N -> 对应台词段”。"""
    text = str(alignment_text or "").replace("\r\n", "\n").replace("\r", "\n")
    matches = list(ALIGNMENT_MAP_HEADER_RE.finditer(text))
    mapping = {}
    if not matches:
        return mapping
    for i, m in enumerate(matches):
        if m.group(1):
            image_no = int(m.group(1))
        else:
            image_no = lrc_image_index_for_label(m.group(2), total_images=total_images)
        if not image_no:
            continue
        first = (m.group(3) or "").strip()
        start = m.end()
        end = matches[i + 1].start() if i + 1 < len(matches) else len(text)
        body = text[start:end]
        lines = []
        if first:
            first = re.sub(r"^\s*(?:对应台词|口播|台词|Voiceover)\s*[：:]\s*", "", first, flags=re.I).strip()
            if first and first not in {"无", "无。", "无对应台词", "无对应台词。", "None", "N/A"}:
                lines.append(first)
        for raw in body.splitlines():
            line = raw.strip()
            if not line:
                continue
            line = re.sub(r"^\s*(?:对应台词|口播|台词|Voiceover)\s*[：:]\s*", "", line, flags=re.I).strip()
            if not line or line in {"无", "无。", "无对应台词", "无对应台词。", "None", "N/A"}:
                continue
            if re.match(r"^\s*(?:提示词|Prompt)\s*[：:]", line, flags=re.I):
                continue
            lines.append(line)
        cleaned = []
        for line in lines:
            line = clean_voiceover_line(line)
            if line:
                cleaned.extend(split_voiceover_preserve_sentences(line))
        if cleaned:
            mapping[image_no] = "\n".join(strip_lrc_image_markers(x) for x in cleaned if strip_lrc_image_markers(x))
        else:
            mapping.setdefault(image_no, "")
    return mapping


def _all_voiceover_sentence_norms(voiceover_text: str) -> list:
    norms = []
    for raw in str(voiceover_text or "").splitlines():
        cleaned = clean_voiceover_line(raw)
        if not cleaned:
            continue
        for sent in split_voiceover_preserve_sentences(cleaned):
            n = normalize_text_for_marker_match(sent)
            if n:
                norms.append((sent, n))
    return norms


def _append_missing_voiceover_to_alignment_map(mapping: dict, voiceover_text: str, logger=None) -> dict:
    """保守补漏：如果图文对应模型漏掉原句，把漏句追加到最后一个非空图号，避免台词丢失。"""
    if not mapping:
        return mapping
    all_aligned_norm = normalize_text_for_marker_match("\n".join(str(v or "") for v in mapping.values()))
    missing = []
    for sent, norm in _all_voiceover_sentence_norms(voiceover_text):
        if norm and norm not in all_aligned_norm:
            missing.append(sent)
    if not missing:
        return mapping
    target = max([k for k, v in mapping.items() if str(v or "").strip()] or list(mapping.keys()))
    extra = "\n".join(strip_lrc_image_markers(x) for x in missing if strip_lrc_image_markers(x))
    mapping[target] = (str(mapping.get(target, "")).strip() + "\n" + extra).strip()
    if logger:
        logger(f"⚠️ 图文对应模型漏掉 {len(missing)} 句台词，已保守追加到图{target}，避免台词丢失。")
    return mapping



def _summarize_voiceover_for_visual_lock(voice: str, limit: int = 150) -> str:
    """把该图对应台词压缩为给图像模型看的语义目标；不改变台词文件。"""
    s = str(voice or "")
    s = LRC_IMAGE_MARKER_RE.sub(" ", s)
    s = re.sub(r"\s+", " ", s).strip()
    s = re.sub(r"^(?:无对应台词|无|None|N/A)\s*$", "", s, flags=re.I)
    if len(s) > limit:
        cut = s[:limit].rstrip(" ,，.;；。")
        last = max(cut.rfind("。"), cut.rfind("！"), cut.rfind("？"), cut.rfind("；"), cut.rfind(";"), cut.rfind("."))
        if last >= 40:
            cut = cut[:last + 1]
        s = cut.strip()
    return s


def _summarize_global_script_theme(voiceover_text: str, limit: int = 520) -> str:
    """从整段口播中提炼整章/整段脚本的总主题，用于 A/C 概括图。

    不取开头钩子当主题；优先用 A2 章节提要句，再补充 2-4 句真正含有
    生物学/机制/结构/实验/疾病/行为概念的内容句。
    """
    raw_sentences = []
    for raw in str(voiceover_text or "").splitlines():
        line = strip_lrc_image_markers(clean_voiceover_line(raw))
        if line and line not in {"无对应台词", "无"}:
            for sent in split_voiceover_preserve_sentences(line):
                sent = strip_lrc_image_markers(sent).strip()
                if sent and sent not in raw_sentences:
                    raw_sentences.append(sent)
    if not raw_sentences:
        return ""

    overview, _overview_idx = find_a2_chapter_overview_sentence("\n".join(raw_sentences))
    skip_re = re.compile(r"(关注|点赞|收藏|转发|下期|下一章|评论区|今天我们先|你有没有想过|最终挑战|欢迎)")
    content_re = re.compile(
        r"(意识|感知|感觉|行动|运动|学习|记忆|突触|递质|受体|离子通道|动作电位|膜电位|神经元|树突|轴突|髓鞘|回路|环路|网络|通路|大脑|脑区|皮层|丘脑|海马|杏仁核|小脑|脑干|细胞|胶质|基因|DNA|蛋白|分子|疾病|障碍|损伤|实验|证据|电极|成像|情绪|恐惧|奖赏|动机|多巴胺)",
        flags=re.I,
    )
    chosen = []
    if overview:
        chosen.append(overview)
    for sent in raw_sentences:
        if sent == overview or skip_re.search(sent):
            continue
        if content_re.search(sent):
            chosen.append(sent)
        if len(chosen) >= 5:
            break
    if not chosen:
        chosen = raw_sentences[:4]
    merged = " ".join(chosen)
    anchors = _voiceover_visual_keywords("\n".join(chosen))
    if anchors:
        merged += f" 视觉锚点：{anchors}."
    merged = re.sub(r"\s+", " ", merged).strip()
    if len(merged) > limit:
        cut = merged[:limit].rstrip(" ,，.;；。")
        last = max(cut.rfind("。"), cut.rfind("！"), cut.rfind("？"), cut.rfind("；"), cut.rfind(";"), cut.rfind("."))
        if last >= 120:
            cut = cut[:last + 1]
        merged = cut.strip()
    return merged


def _extract_global_script_theme_from_prompt(prompt: str) -> str:
    raw = str(prompt or "").replace("\r\n", "\n").replace("\r", "\n")
    m_line = re.search(r"GLOBAL\s+SCRIPT\s+THEME\s*/\s*全章主题锚点\s*[：:]\s*([^\n]{2,700})", raw, flags=re.I)
    if m_line:
        return _summarize_voiceover_for_visual_lock(m_line.group(1), limit=320)
    m = re.search(r"GLOBAL\s+SCRIPT\s+THEME\s*/\s*全章主题锚点\s*[：:]\s*(.+?)(?=\s*(?:PAIRED\s+VOICEOVER|Page\s*Type|Hard\s+rule:|Required\s+composition:|Original\s+draft\s+prompt\s+below))", raw, flags=re.I | re.S)
    if m:
        return _summarize_voiceover_for_visual_lock(m.group(1), limit=320)
    # 兜底：如果显式全章主题没有被写入，也尝试从当前提示词中的完整口播、章节提要或元信息里提炼。
    # 这样 A1/A2/A01/A02/C 不会退回成泛脑图、品牌氛围图或无关章节背景。
    fallback = _summarize_global_script_theme(raw, limit=320)
    if fallback and len(re.sub(r"\s+", "", fallback)) >= 12:
        return fallback
    field_bits = []
    for pat in [
        r"(?:中文章节名|章节中文名|Chapter\s*Title\s*CN)\s*[：:=]\s*([^\n]{2,160})",
        r"(?:英文章节名|章节英文名|原始章节名|Chapter\s*Title(?:\s*EN)?)\s*[：:=]\s*([^\n]{2,180})",
        r"(?:本章(?:核心|主线|总结|主题)|整章(?:总结|主题)|Full\s*Chapter\s*(?:Summary|Theme))\s*[：:=]\s*([^\n]{2,260})",
    ]:
        for mm in re.finditer(pat, raw, flags=re.I):
            val = re.sub(r"\s+", " ", mm.group(1)).strip(" ，,.;；。")
            if val and val not in field_bits:
                field_bits.append(val)
            if len(field_bits) >= 4:
                break
        if len(field_bits) >= 4:
            break
    return _summarize_voiceover_for_visual_lock("；".join(field_bits), limit=320) if field_bits else ""


def _strict_b_visual_target_from_voiceover(voice: str) -> str:
    """为 B 系列生成更硬的台词专属视觉目标，避免关键词误命中导致跑题。"""
    t = re.sub(r"\s+", " ", str(voice or "")).strip()
    if not t:
        return ""
    rules = [
        (r"兴奋性.*抑制性|抑制性.*兴奋性|谷氨酸.*GABA|GABA.*谷氨酸|AMPA|NMDA|GABA_A|去极化|超极化|氯离子通透", "show a side-by-side comparison of an excitatory glutamatergic synapse versus an inhibitory GABA_A synapse, with transmitter release, receptor type, dominant ion flow, and the resulting depolarizing versus stabilizing/hyperpolarizing postsynaptic effect"),
        (r"离子型.*代谢型|代谢型.*离子型|ionotropic|metabotropic|G蛋白|第二信使", "show a comparison of ionotropic receptor signaling versus metabotropic receptor signaling: direct ion-channel gating and fast effect versus slower G-protein/second-messenger pathway"),
        (r"突触整合|整合输入|树突.*胞体|胞体.*轴突初段|轴突初段|EPSP|IPSP|空间总和|时间总和", "show multiple excitatory and inhibitory synaptic inputs converging on dendrites and soma, being integrated at the axon initial segment to determine whether an action potential is generated"),
        (r"突触后致密区|PSD|gephyrin|GKAP|SHANK|HOMER|collybistin|neuroligin", "show the postsynaptic scaffold organization beneath excitatory versus inhibitory synapses, emphasizing PSD-like scaffold at excitatory sites and gephyrin-based scaffold at inhibitory sites"),
        (r"肾上腺提取物|Oliver|Schaefer|升高血压", "show adrenal extract injection leading to blood-vessel / blood-pressure response and target-tissue physiological effect; do not draw kidney nephron or kidney filtration"),
        (r"Elliott|类似肾上腺素|神经冲动到达外周|可扩散、可识别的分子事件", "show a peripheral nerve terminal carrying an action potential that triggers release of an adrenaline-like chemical messenger toward a nearby target tissue"),
        (r"Loewi|蛙心|迷走神经", "show Loewi-style frog-heart / vagus-nerve stimulation evidence: nerve terminal releases acetylcholine-like messenger and the heart response changes"),
        (r"四步|合成和储存|释放|受体|移除", "show the four-step chemical synaptic transmission chain: synthesis/storage -> vesicular release -> receptor binding -> removal/clearance"),
        (r"合成.*囊泡|囊泡.*胞吐|释放量", "show presynaptic synthesis, vesicle accumulation at release site, and exocytosis toward the postsynaptic target"),
        (r"外源.*模拟|内源递质|离子通道|第二信使|移除", "show exogenous transmitter mimicry activating the same receptor/channel or second-messenger pathway, plus a specific clearance mechanism"),
        (r"有线|私人|容量|社会性|突触外空间|扩散", "show a side-by-side comparison: private wired synapse limited to one cleft versus volume transmission diffusing through extracellular space to multiple synapses"),
        (r"小分子递质|神经活性肽|乙酰胆碱|生物胺|氨基酸|ATP|腺苷", "show a comparison of small-molecule neurotransmitters versus neuroactive peptides, with distinct vesicle classes and examples implied by molecular categories without readable text"),
        (r"直径约四十纳米|电子透明|致密核心囊泡|高尔基体|七十到二百五十纳米", "show small clear synaptic vesicles near the axon terminal versus larger dense-core vesicles processed through Golgi, emphasizing size/packaging difference"),
        (r"钙离子|主动区|膜融合|胞吐|动作电位", "show action potential arriving at presynaptic terminal, calcium entry, vesicle fusion at active zone, and exocytosis"),
        (r"主动摄取进囊泡|可释放的囊泡库|不是自然散落", "show vesicular transporter loading small neurotransmitter molecules into synaptic vesicles, forming a releasable vesicle pool rather than free scattered molecules"),
        (r"共同释放|共释放|多种化学成分|最后一步是清除|再摄取|降解|扩散", "show co-release of small molecule and peptide from one terminal, followed by clearance routes: diffusion, reuptake transporter, and enzymatic degradation"),
        (r"自身受体|限制后续释放|抑制后续合成", "show autoreceptor feedback on the presynaptic terminal reducing later transmitter release or synthesis"),
        (r"异源受体|突触前释放部位|其他神经元|调节突触前兴奋性", "show heteroreceptor control: input from another neuron acts on a presynaptic receptor to modulate terminal excitability and transmitter release"),
        (r"短到不到一毫秒|持续数秒|后果一定短暂|反馈控制|突触前调节", "show short receptor binding at the synapse contrasted with downstream functional effects and feedback/presynaptic modulation"),
        (r"细胞内过程|数小时|数天|基因转录", "show receptor activation leading to intracellular signaling cascade reaching the nucleus and changing gene transcription over hours to days"),
        (r"星形胶质|小胶质|非神经细胞|合成、储存、释放递质|表达.*受体", "show astrocyte and microglia in the synaptic microenvironment synthesizing/storing/releasing transmitter and expressing receptors"),
        (r"靶细胞.*神经元|肌肉|腺体|激素.*血液|远处目标", "show local neurotransmitter action on nearby neuron/muscle/gland versus hormone entering blood circulation to distant targets"),
        (r"制造并释放特定化学物质|靶细胞.*受体|功能改变|第一近似定义", "show neuron releasing a defined chemical messenger onto target-cell receptors that convert chemical information into a functional change"),
        (r"什么样的化学物质.*资格.*神经递质|心跳变慢|肌肉收缩", "show the core question as a mechanistic scene: a small chemical messenger from a synaptic terminal changing heart or muscle target activity through receptor interaction"),
        (r"不是.*化学结构决定|经验性、操作性|不断扩展", "show the neurotransmitter concept as criteria-based evidence framework around a synapse, not as a simple chemical-structure icon"),
    ]
    for pat, desc in rules:
        if re.search(pat, t, flags=re.I):
            return desc
    return ""


def _voiceover_visual_keywords(voice: str) -> str:
    """从对应台词中提取可视化关键词；只保留强命中，避免把 B 图带到无关器官/泛分子。"""
    t = str(voice or "")
    strict = _strict_b_visual_target_from_voiceover(t)
    hits = [strict] if strict else []
    pairs = [
        (r"兴奋性|谷氨酸|AMPA|NMDA|去极化", "excitatory synapse, glutamate release, AMPA/NMDA-type receptor, cation influx, depolarizing postsynaptic effect"),
        (r"抑制性|GABA|GABA_A|氯离子|超极化", "inhibitory synapse, GABA release, GABA_A receptor, chloride influx, stabilizing or hyperpolarizing postsynaptic effect"),
        (r"离子型|ionotropic", "ligand-gated ion channel receptor with fast membrane response"),
        (r"代谢型|metabotropic|G蛋白|第二信使", "metabotropic receptor with G-protein or second-messenger signaling"),
        (r"突触整合|整合输入|EPSP|IPSP|轴突初段|空间总和|时间总和", "multiple excitatory and inhibitory inputs converging on dendrites and soma, integration at the axon initial segment"),
        (r"突触后致密区|PSD|gephyrin|GKAP|SHANK|HOMER|collybistin|neuroligin", "postsynaptic scaffold proteins organizing excitatory or inhibitory synapses"),
        (r"神经递质|递质|突触间隙|突触传递|突触", "synaptic terminal, neurotransmitter vesicles, synaptic cleft, postsynaptic receptors"),
        (r"乙酰胆碱|生物胺|氨基酸类递质|ATP|腺苷|神经活性肽", "defined neurotransmitter molecule classes and vesicle packaging"),
        (r"囊泡|胞吐|主动区|释放部位|可释放", "synaptic vesicles docking/fusing at the presynaptic active zone"),
        (r"受体|离子通道|第二信使|自身受体|异源受体", "specific receptor interaction, ion channel or second-messenger pathway"),
        (r"再摄取|降解|清除|移除", "transmitter clearance by diffusion, reuptake transporter, or enzymatic degradation"),
        (r"动作电位|电信号|膜电位|钙离子", "action potential arriving at axon terminal, calcium entry, release trigger"),
        (r"轴突|树突|神经元|突触前|突触后", "presynaptic neuron, postsynaptic target cell, axon terminal and dendrite relationship"),
        (r"星形胶质|小胶质|胶质", "glial cells participating in synaptic chemical signaling"),
        (r"高尔基体|致密核心囊泡", "Golgi processing and dense-core vesicle packaging"),
        (r"心跳|心脏|蛙心|心率", "heart target response connected to chemical neural signaling"),
        (r"血压|血管", "blood-vessel / blood-pressure physiological response"),
        (r"肌肉|腺体|效应器官", "muscle or gland target effector responding to neurotransmitter"),
        (r"激素|内分泌|血液", "hormone signal traveling through blood to distant target"),
        (r"基因转录|转录|基因|DNA|蛋白", "intracellular signaling to nucleus and gene transcription"),
        (r"实验|证据|记录|电极|成像|Loewi|Ewins|Elliott|Oliver|Schaefer", "experimental evidence scene supporting the neurotransmitter concept"),
    ]
    for pat, desc in pairs:
        if re.search(pat, t, flags=re.I):
            hits.append(desc)
    dedup = []
    for h in hits:
        if h and h not in dedup:
            dedup.append(h)
    return "; ".join(dedup[:4])

def _voiceover_logic_relation_brief(voice: str) -> str:
    """从台词里提取需要被画面构图呼应的逻辑关系。"""
    t = re.sub(r"\s+", " ", str(voice or "")).strip()
    if not t:
        return ""
    relations = []
    checks = [
        (r"因为|由于|因此|所以|从而|导致|引起|造成|使得|触发|驱动|决定|影响|改变|激活|抑制|增强|削弱|调节", "cause-to-effect relationship; make the visual flow show what drives what and what changes as a result"),
        (r"先|然后|接着|随后|最终|最后|起初|之后|在.*之前|在.*之后|逐渐|过程|阶段|步骤|时间", "temporal or stepwise sequence; arrange the scene as an ordered process rather than a static collage"),
        (r"但|但是|然而|不过|不是.*而是|相反|反而|转而|却", "contrast or reversal; show the before/after shift or opposing states clearly"),
        (r"相比|对比|不同|差异|一方面|另一方面|同时|分别|两种|两类|兴奋性|抑制性|离子型|代谢型|快|慢", "comparison; show the two states, groups, or pathways side by side with visible differences"),
        (r"不仅|还|进一步|更|尤其|核心|关键|递进|层层|逐步", "progressive emphasis; use hierarchy, zoom-in, or layered composition to show the added or deeper mechanism"),
        (r"如果|当.*时|一旦|条件|取决于|依赖", "conditional relationship; make the triggering condition and downstream response visually connected"),
        (r"通过|依靠|参与|介导|连接|传递|整合|反馈|环路|通路|路径|机制|系统", "mechanistic linkage; show functional connections, information flow, feedback, pathway, or circuit organization"),
        (r"证据|实验|研究|记录|观察|测量|成像|发现|显示|表明", "evidence-to-claim relationship; show the observation or experimental readout supporting the concept"),
    ]
    for pat, desc in checks:
        if re.search(pat, t, flags=re.I) and desc not in relations:
            relations.append(desc)
    return "; ".join(relations[:3])

def _extract_paired_voiceover_from_prompt(prompt: str) -> str:
    """从已注入语义锁的提示词里提取配对台词，用于最终 API 提示词重建。"""
    raw = str(prompt or "").replace("\r\n", "\n").replace("\r", "\n")
    m = re.search(r"PAIRED\s+VOICEOVER\s*/\s*文案语义锁\s*[：:]\s*(.+?)(?=\s*(?:LOGIC\s+RELATION|Hard\s+rule:|Required\s+composition:|Original\s+draft\s+prompt\s+below))", raw, flags=re.I | re.S)
    if m:
        return _summarize_voiceover_for_visual_lock(m.group(1), limit=260)
    return ""


def _anti_atmospheric_teaching_lock(page_type: str = "") -> str:
    """进一步压制氛围化、装饰化、海报化倾向。"""
    page = str(page_type or "").strip()
    is_content = bool(re.search(r"\bB\b|Main\s+Content|内容", page, flags=re.I))
    is_home_or_cover = bool(re.search(r"A1|A2|A01|A02|Cover|Home|封面|首页", page, flags=re.I))
    lines = [
        "Anti-atmosphere lock: this image must function as a teaching figure, not as a mood piece, poster, splash art, or decorative wallpaper.",
        "Do not use cinematic hero-shot composition, dramatic rim light, theatrical spotlight, exaggerated perspective, shallow depth of field, glossy advertising look, or stylized spectacle.",
        "Do not fill space with abstract smoke, random particles, floating symbols, empty gradients, decorative flares, or purely aesthetic background texture.",
        "Favor clean explanatory layout, neutral background, stable viewpoint, moderate depth, and didactic object placement over emotional atmosphere.",
        "Every visible element should earn its place by teaching the current concept; if it is only decorative, remove it.",
    ]
    if is_content:
        lines.append("For B-series specifically: prefer textbook panel / mechanism diagram / comparison diagram / process diagram / evidence diagram feeling, not poster art. The scene must concretely and vividly depict the specific narration rather than merely repeating broad keywords. Show only the sentence-level subject, action, and result, with minimal but useful keyword annotations.")
    elif is_home_or_cover:
        lines.append("For A-series: even though it summarizes the chapter, it must still read like a clean educational concept-map background rather than a cinematic medical poster.")
    else:
        lines.append("Keep the image academically restrained and explanation-first.")
    return " ".join(lines).strip()


def _scientific_accuracy_prompt_lock(voice: str, page_type: str = "") -> str:
    """给教育向内容增加更强的科学准确性约束。"""
    t = re.sub(r"\s+", " ", str(voice or "")).strip()
    page = str(page_type or "").strip()
    is_content = bool(re.search(r"\bB\b|Main\s+Content|内容", page, flags=re.I))
    lines = [
        "Educational accuracy lock: this image is for science education. Prefer conservative, textbook-grade, source-supported depiction over dramatic or decorative rendering.",
        "Do not invent anatomy, diseases, cell types, pathways, molecules, experimental apparatus, species, or causal claims that are not explicitly supported by the paired voiceover or the chapter-level prompt.",
        "If the narration is conceptual rather than structural, visualize the concept with the minimal necessary biomedical scene instead of adding extra mechanistic details.",
        "If there is any ambiguity, choose the narrower, safer interpretation and keep the depiction generic-but-correct rather than specific-but-unsupported.",
        "Do not mix neighboring concepts into the current shot. Each image must teach only the current sentence or tightly linked sentence pair.",
    ]
    if re.search(r"Loewi|Ewins|Elliott|Oliver|Schaefer|蛙心|肾上腺提取物|历史|实验|证据", t, flags=re.I):
        lines.append("Historical evidence lock: show only the experiment or observation explicitly mentioned; do not add later discoveries, modern equipment, or unrelated organs unless stated.")
    if re.search(r"定义|标准|第一近似定义|四个标准|不是.*而是", t, flags=re.I):
        lines.append("Definition/criteria lock: compose the image as a precise criteria-based teaching figure or comparison, not as a generic molecular wallpaper.")
    if re.search(r"比较|两类|不同|差异|相比|一方面|另一方面|有线|私人|容量|社会性", t, flags=re.I):
        lines.append("Comparison lock: the two categories or states must be visually separable and not blended into one ambiguous scene.")
    if re.search(r"过程|步骤|四步|合成|储存|释放|受体|移除|清除|胞吐|再摄取", t, flags=re.I):
        lines.append("Process lock: make the order of steps visually explicit and biologically plausible; do not scramble the sequence.")
    if is_content:
        lines.append("For B-series specifically: accuracy and semantic alignment are more important than visual richness. If a decorative element does not teach the paired voiceover, remove it. Use only minimal keyword annotation: add 2-4 English keyword labels total when they improve clarity, each 1-2 words, with no explanatory sentences.")
    return " ".join(lines).strip()


def _build_voiceover_grounded_visual_brief(voice: str, page_type: str = "", original_prompt: str = "") -> str:
    """把配对台词或全章主题重写成最终绘图 brief。

    v140 reset:
    - 不再把 original_prompt 作为 supplemental style/context 拼回最终 API 提示词；
    - B 图最终主体只由对应台词 + 逻辑关系锁决定；
    - 旧版泛化背景、留白、安全区、Logo、参考线等配置全部不能进入 AI Prompt。
    """
    summary = _summarize_voiceover_for_visual_lock(voice, limit=320)
    anchors = _voiceover_visual_keywords(voice)
    logic_brief = _voiceover_logic_relation_brief(voice)
    page = str(page_type or "").strip()
    is_content = bool(re.search(r"\bB\b|Main\s+Content|内容", page, flags=re.I))
    is_home_or_cover = bool(re.search(r"A1|A2|Cover|Home|封面|首页", page, flags=re.I))
    is_brand = bool(re.search(r"Brand|Ending|Final|品牌|结尾", page, flags=re.I))

    if not summary:
        # 没有台词锁时，只保留当前 prompt 中清洗后的具体视觉主体；不得回退到旧泛化背景。
        cleaned = strip_public_elements_for_raw_generation(original_prompt, role=detect_visual_role(page, original_prompt))
        cleaned = _compact_generation_prompt_text(cleaned, max_chars=420)
        if cleaned:
            return cleaned
        return "No-text biomedical illustration must use a concrete source-supported visual subject and an explicit logical relationship; do not use a generic background."

    lines = []
    if is_content:
        strict_target = _strict_b_visual_target_from_voiceover(voice)
        lines.append(f"B-content keyword visual brief from paired voiceover only: {summary}.")
        if strict_target:
            lines.append(f"Mandatory visual target: {strict_target}.")
        lines.append("Goal: match the current voiceover exactly and show one clear biomedical relationship, not a generic topic background.")
        lines.append("Shot-focus rule: each B image must serve only one sentence or one tightly linked short sentence group. Explicitly depict the main subject, the interacting object or context, the key action/process, the change/result, and the before-after or input-output relation when present.")
        lines.append("Use objects, arrows, contrast, and spatial layout to teach the relation; do not rely on written explanation inside the image.")
        lines.append("Element filtering rule: include only the objects needed to teach this exact short voiceover segment. Do not restack repeated chapter motifs or neighboring-shot concepts unless the current voiceover explicitly requires them.")
        lines.append("B text policy: keep text minimal but not absent when clarity benefits. Use 2-4 concise English keyword labels/callouts total when helpful, each 1-2 words. No title, heading, paragraph, caption, numbered steps, table, explanation box, or Chinese text.")
        lines.append("Keep one dominant biomedical subject and one relationship structure: cause-effect, comparison, sequence, hierarchy, input-output, condition-result, evidence-claim, or problem-explanation.")
        lines.append("Accuracy override: show only objects supported by the paired voiceover; remove neighboring-shot details and decorative filler.")
    elif is_home_or_cover:
        lines.append(f"A1/A2/A01/A02 shared no-text master background as a full-chapter summary key visual: {summary}.")
        lines.append("It must function as a chapter-level concept map without text: opening problem -> core biomedical objects -> mechanism/evidence relationship -> conclusion. No labels, no letters, no numbers, no logo, no watermark, and no pseudo-text.")
        lines.append("Mandatory richness for A-series: show at least 3 concrete source-supported visual components and make their relationship explicit, such as organ or brain-region level object + cellular or molecular mechanism + evidence or state-change cue. If the chapter spans multiple scales, the composition should visibly connect macro and micro levels.")
        lines.append("A-series anti-poster rule: this is a summary concept map, not a dramatic chapter poster. Avoid mood-first lighting, giant floating hero objects, and decorative empty space.")
        lines.append("Do not reduce the chapter to a generic brain, neuron, DNA, cell, synapse, molecule, blue medical wallpaper, or isolated biology symbol.")
    elif is_brand:
        lines.append(f"C ending no-text background as a full-chapter summary plus next-question key visual: {summary}.")
        lines.append("It must visually recap the chapter's established concept relationship and leave an open connection to the next chapter theme without inventing unsupported details. C raw background should contain no visible text, no letters, no numbers, no logo, no watermark, and no pseudo-text.")
        lines.append("Mandatory richness for C page: recap 2-4 concrete chapter elements and their relationship; do not fade into a generic brand atmosphere, soft particles, abstract brain wallpaper, or decorative biology icon.")
        lines.append("C-page anti-atmosphere rule: keep the page clean and instructional; the close should still look like a restrained educational recap, not an ad poster or mood board.")
    else:
        lines.append(f"Visualize the paired narration directly: {summary}.")

    if anchors:
        lines.append(f"Concrete biomedical anchors to consider and visibly instantiate as real subjects: {anchors}.")
        lines.append("Anchor conflict rule: anchors are only helpers. If any anchor would make the image less accurate than the paired voiceover, drop that anchor immediately.")
    if logic_brief:
        lines.append(f"Required logical relationship: {logic_brief}.")
    else:
        lines.append("Required logical relationship: infer the main relation from the narration and make it visible through composition; do not merely place related objects together.")

    lines.append("Composition must express the relationship through one clean spatial structure: directional flow, side-by-side contrast, staged sequence, zoom hierarchy, converging inputs, diverging outputs, feedback loop, or evidence-to-claim structure as appropriate. Do not express the idea through many text blocks or many boxed subpanels.")
    lines.append(_scientific_accuracy_prompt_lock(voice, page_type=page))
    lines.append(_anti_atmospheric_teaching_lock(page_type=page))
    if is_home_or_cover or is_brand:
        lines.append("Do not output a lone centered biology symbol. The image should read like a summary figure or concept-map composition with multiple related components, not like wallpaper.")
    if is_content:
        lines.append("Style: clean biomedical textbook figure, one readable scene, stronger three-dimensional volume than a flat icon diagram, crisp contour linework, light neutral background, restrained accent colors, layered depth cues, realistic tissue/material form, textbook clarity first; no sci-fi, no neon brain, no poster spectacle, no advertising polish, no cinematic glamour.")
        lines.append("B-series annotation rule: use only minimal labels. Add 2-4 English keyword labels/callouts total when they materially improve scientific clarity, each 1-2 words. Keywords only; no sentences, title, numbered steps, bullet list, explanation box, table, paragraph, long caption, Chinese text, logo, watermark, pseudo-text, or fake text block.")
    else:
        lines.append("Style: explanation-first biomedical illustration, slightly three-dimensional but still diagrammatic, crisp contour linework, clear anatomy and structure relationships, light neutral or white background, restrained accent colors, soft dimensional shading, matte surfaces, medically plausible morphology, readable depth, callout-friendly composition; textbook-grade clarity first; no sci-fi, no neon brain, no futuristic interface, no flashy CGI, no poster-like spectacle, no advertising polish, no cinematic glamour.")
        lines.append("Raw image only: No visible text, no letters, no numbers, no logo, no labels, no watermark, no pseudo-text, no UI, no HUD, no neon sci-fi, no decorative random particles.")
    return " ".join(lines).strip()


def _append_visual_copy_relevance_lock(prompt: str, voice: str, page_type: str = "") -> str:
    """把最终绘图提示词改成“台词驱动”。

    v130 修复重点：不再只是把一句相关性说明附加在旧 Prompt 前面；
    旧 Prompt 只能作为风格参考，画面主体必须由该图对应台词决定。
    """
    base = str(prompt or "").strip()
    target = _summarize_voiceover_for_visual_lock(voice, limit=320)
    if not base or not target:
        return base

    if "PAIRED VOICEOVER / 文案语义锁" in base or "VOICEOVER-DRIVEN IMAGE BRIEF" in base:
        return base

    page = str(page_type or "").strip() or infer_alignment_page_type("", base)
    is_content = bool(re.search(r"\bB\b|Main\s+Content|内容", page, flags=re.I))
    is_home_or_cover = bool(re.search(r"A1|A2|Cover|Home|封面|首页", page, flags=re.I))
    is_brand = bool(re.search(r"Brand|Ending|Final|品牌|结尾", page, flags=re.I))
    visual_keywords = _voiceover_visual_keywords(voice)
    logic_brief = _voiceover_logic_relation_brief(voice)
    global_theme = _extract_global_script_theme_from_prompt(base)

    if is_content:
        strict_target = _strict_b_visual_target_from_voiceover(voice)
        role_line = (
            "This is a B-series content image. The foreground must be a specific biomedical mechanism/scene derived from the paired voiceover, "
            "not a generic brain, neuron wallpaper, DNA decoration, abstract blue science background, or unrelated textbook filler. "
            + (f"Mandatory visual target: {strict_target}. " if strict_target else "")
            + "Do not add organs, diseases, DNA/protein scenes, kidney structures, or unrelated anatomy unless they are explicitly present in the paired voiceover. "
            + "It should read like one clean teaching diagram, not a cinematic poster, mood image, or decorative splash art. Prefer zero visible text; if needed, use only 1-3 English keyword labels/callouts total, each 1-2 words; no tables, no paragraphs, no captions, no headings."
        )
    elif is_brand:
        role_line = (
            "This is the final brand/end page background. It may be softer and cleaner, but its biological elements must still echo the paired closing voiceover topic."
        )
    elif is_home_or_cover:
        role_line = (
            "This is an A-series cover/home background. A1, A2, A01, and A02 must all reuse the same single full-chapter-summary background. The visible biology motif must echo the whole chapter topic in the paired voiceover; do not include typography placeholders, generic wallpaper, or unrelated chapter motifs."
        )
    else:
        role_line = (
            "The image must be determined by the paired voiceover meaning, with a clear biomedical subject and no generic filler background."
        )

    keyword_line = f"Concrete biomedical anchors from the voiceover, after strict filtering: {visual_keywords}. If any anchor conflicts with the exact paired voiceover, ignore the anchor and follow the paired voiceover." if visual_keywords else "Choose the concrete biomedical subject directly from the paired voiceover; do not use old prompt background defaults."
    logic_line = f"LOGIC RELATION / 逻辑关系锁：{logic_brief}" if logic_brief else "LOGIC RELATION / 逻辑关系锁：Infer the main relationship from the narration and make it visible; show cause-effect, comparison, sequence, hierarchy, transition, condition, evidence, input-output, or mechanism when present."

    theme_line = f"GLOBAL SCRIPT THEME / 全章主题锚点：{global_theme}\n" if global_theme else ""
    if global_theme and (is_home_or_cover or is_brand):
        role_line = (
            "For A/C pages, summarize the GLOBAL SCRIPT THEME as one coherent no-text full-chapter biomedical concept map. For A1/A2/A01/A02, use one shared master background reused by crop only: "
            "opening problem -> core objects -> mechanism/evidence chain -> conclusion or next-question relation. "
            "Do not shrink it into a decorative background, generic biology symbol, generic brain/neuron/DNA/cell icon, soft particles, or brand atmosphere."
        )
    rewritten = f"""VOICEOVER-DRIVEN KEYWORD IMAGE BRIEF — highest priority.
{theme_line}PAIRED VOICEOVER / 文案语义锁：{target}
{logic_line}

Draw one clean biomedical teaching figure that matches the paired voiceover above. Do not visualize a different sentence and do not render the voiceover as text.
{role_line}
{keyword_line}

Scene construction protocol: this single image must serve only the current sentence or tightly linked short sentence group. Explicitly show the main subject, interacting object/context, key action or process, resulting state change or outcome, and before-after or input-output relation when present.
Element filtering rule: include only elements necessary for this exact short voiceover segment. Do not recycle whole-chapter motifs, repeat broad topic symbols, or pile up related objects that are not part of the current logic.
Composition: one main biomedical subject; one clear relationship structure such as cause-effect, comparison, sequence, hierarchy, input-output, condition-result, evidence-claim, or mechanism.
B visible text policy: keep text minimal but not absent when clarity benefits. If labels help, use 2-4 English keyword labels/callouts total, each 1-2 words. Keywords only. No title, heading, paragraph, caption, explanation box, numbered steps, bullet list, table, dense labels, Chinese text, logo, watermark, or pseudo-text.
Style: professional biomedical textbook illustration, crisp contour linework, light neutral background, restrained academic palette, stronger three-dimensional volume with readable depth, anatomically plausible form, and clean diagram clarity; no sci-fi, neon, cinematic poster, decorative particles, or generic wallpaper.
OLD DRAFT PROMPT SUPPRESSED: previous generic backgrounds and style-only wallpaper prompts must not be used.
"""
    return rewritten.strip()


# ================== Gemini/外部模型兜底：强制按 3~8 秒密度重建 B 系列 ==================
def _estimate_voiceover_seconds_for_visual_segment(text: str) -> float:
    """估算一段中文口播时长；只用于分镜密度兜底，不写入 LRC 时间戳。"""
    s = strip_lrc_image_markers(str(text or ""))
    s = re.sub(r"\s+", "", s)
    if not s:
        return 0.0
    # 中文科普口播常见 4.8~5.8 字/秒。这里取 5.2，宁可多拆图，避免 20~60 秒挤一张 B 图。
    cjk = len(re.findall(r"[\u4e00-\u9fff]", s))
    alnum = len(re.findall(r"[A-Za-z0-9]+", s))
    other = max(0, len(re.sub(r"[\u4e00-\u9fffA-Za-z0-9，,。.!！?？；;：:\s、（）()《》“”\"'·\-—_+/]", "", s)))
    units = cjk + max(1, alnum) * 2 + other
    return max(0.8, units / 5.2)


def _split_sentence_to_visual_clauses(sentence: str, max_seconds: float) -> list[str]:
    """长句按逗号/分号/冒号等切成可承载的视觉小段。"""
    s = strip_lrc_image_markers(str(sentence or "")).strip()
    if not s:
        return []
    if _estimate_voiceover_seconds_for_visual_segment(s) <= max_seconds:
        return [s]
    # 保留分隔标点，尽量不断掉科学术语所在短语。
    parts = re.findall(r"[^，,；;：:。！？!?]+[，,；;：:。！？!?]?", s)
    out = []
    max_chars = max(22, int(float(max_seconds or 8.0) * 5.2))
    for part in parts:
        part = part.strip()
        if not part:
            continue
        if _estimate_voiceover_seconds_for_visual_segment(part) <= max_seconds or len(part) <= max_chars:
            out.append(part)
        else:
            # 极长无标点句再按长度硬切，避免模型把很长机制压进一张图。
            for i in range(0, len(part), max_chars):
                chunk = part[i:i + max_chars].strip()
                if chunk:
                    out.append(chunk)
    return out


def _split_sentences_to_3_8s_visual_segments(sentences: list[str]) -> list[str]:
    """把连续台词拆成 3~8 秒左右的 B 图片段。"""
    min_s = float(globals().get("MIN_SECONDS_PER_IMAGE", 3.0) or 3.0)
    max_s = float(globals().get("MAX_SECONDS_PER_IMAGE", 8.0) or 8.0)
    # 用户明确要求 3~8s：即使环境变量仍设成 5，也允许上限到 8；低于 3 不再继续切碎。
    min_s = max(3.0, min_s)
    max_s = max(8.0, max_s)
    clauses = []
    for sent in sentences or []:
        clauses.extend(_split_sentence_to_visual_clauses(sent, max_s))
    segments = []
    cur = []
    cur_s = 0.0

    def flush():
        nonlocal cur, cur_s
        if cur:
            joined = "\n".join(x.strip() for x in cur if x.strip()).strip()
            if joined:
                segments.append(joined)
        cur = []
        cur_s = 0.0

    for clause in clauses:
        sec = _estimate_voiceover_seconds_for_visual_segment(clause)
        if cur and cur_s >= min_s and cur_s + sec > max_s:
            flush()
        cur.append(clause)
        cur_s += sec
        # 已经达到上限，立即收束，保证不会出现一张图覆盖超长台词。
        if cur_s >= max_s:
            flush()
    flush()

    # 尾段太短时，尽量并入前一段；如果会超过 8s 太多，则保留。
    if len(segments) >= 2 and _estimate_voiceover_seconds_for_visual_segment(segments[-1]) < min_s:
        last = segments.pop()
        merged = (segments[-1].rstrip() + "\n" + last).strip()
        if _estimate_voiceover_seconds_for_visual_segment(merged) <= max_s * 1.15:
            segments[-1] = merged
        else:
            segments.append(last)
    return [s for s in segments if str(s or "").strip()]


def _choose_closing_sentences_for_c(voiceover_text: str, sentences: list[str]) -> tuple[list[str], set[int]]:
    """选择 C 页结尾台词：优先从“到这里/下一章/关注”起到结尾。"""
    if not sentences:
        return [], set()
    start = -1
    trigger = re.compile(r"(到这里|留下了?下一|下一步|下一章|下期|关注我们|关注|继续讲|总结)")
    for i in range(len(sentences) - 1, -1, -1):
        if trigger.search(sentences[i]):
            start = i
    if start < 0 or len(sentences) - start > 5:
        start = max(0, len(sentences) - 3)
    idxs = set(range(start, len(sentences)))
    return [sentences[i] for i in range(start, len(sentences))], idxs


def _normalize_b_prompt_name_sequence(prompts: list[tuple[str, str]], logger=None):
    """确保最终输出的 B 序号与图片序号连续一致，避免 B01/B03 跳号或数量对不上。"""
    if not prompts:
        return prompts
    total = len(prompts)
    out = []
    b_counter = 0
    renamed = 0
    for i, (name, prompt) in enumerate(prompts, 1):
        page_type = infer_alignment_page_type(name, prompt, i, total)
        is_b = bool(re.search(r"^\s*B\b|Main\s*Content", page_type, flags=re.I) or re.search(r"^B\d+", str(name or ""), flags=re.I))
        if is_b:
            b_counter += 1
            new_name = f"B{b_counter:02d}"
            if str(name or "").strip() != new_name:
                renamed += 1
            out.append((new_name, prompt))
        else:
            out.append((name, prompt))
    if logger and renamed:
        logger(f"🔢 已统一 B 系列图片序号：连续重排为 B01–B{b_counter:02d}，避免台词序号与图片序号不一致。")
    return out


def _make_b_prompt_from_voice_segment(segment: str) -> str:
    """根据一段 3~8 秒台词生成 B 图基础提示词：台词相关、关键词示意、少文字。"""
    voice = re.sub(r"\s+", " ", str(segment or "")).strip()
    logic = _voiceover_logic_relation_brief(voice) if "_voiceover_logic_relation_brief" in globals() else "Infer the main scientific relationship and make it visible"
    strict_target = _strict_b_visual_target_from_voiceover(voice) if "_strict_b_visual_target_from_voiceover" in globals() else ""
    return (
        "Page Type: B. Main Content Page\n"
        "VOICEOVER-DRIVEN KEYWORD IMAGE BRIEF — highest priority.\n"
        f"PAIRED VOICEOVER / 文案语义锁：{voice}\n"
        f"LOGIC RELATION / 逻辑关系锁：{logic};\n"
        + (f"MANDATORY VISUAL TARGET: {strict_target}.\n" if strict_target else "")
        + "B-SERIES KEYWORD STYLE LOCK: draw one clean biomedical teaching figure that matches this exact voiceover; "
        "show the relationship through objects, arrows, contrast, and spatial layout rather than written explanation; "
        "one main visual focus only, single panel or very simple side-by-side comparison; "
        "visible text should be zero by default; if needed, use only 1-3 English keyword labels/callouts total, each 1-2 words; "
        "no title, heading, paragraph, caption, explanation box, numbered steps, bullet list, table, dense labels, Chinese text, logo, watermark, or pseudo-text; "
        "clean professional biomedical textbook illustration, light neutral background, restrained colors, crisp contour linework, slight dimensional depth; "
        "no poster, no infographic board, no decorative wallpaper, no neighboring-shot details."
    )

def _is_b_prompt_empty_shell(prompt: str) -> bool:
    """判断 B 系列提示词是否只是 Page Type / 空壳，避免数量够但内容不可画。"""
    raw = str(prompt or "").strip()
    if not raw:
        return True
    _, body = _split_leading_page_type_and_body(raw)
    if not body and re.search(r"(?is)^\s*Page\s*Type\s*[：:]\s*B\b", raw):
        return True
    body = re.sub(r"(?is)^\s*(?:AI\s+Image\s+Layer\s+Prompt|AI\s+Prompt|Prompt|提示词)\s*[：:]\s*", "", body).strip()
    body = re.sub(r"(?im)^\s*Page\s*Type\s*[：:].*?$", "", body).strip()
    compact = re.sub(r"\s+", " ", body).strip()
    if len(compact) < 80:
        return True
    lower = raw.lower()
    quality_markers = [
        "biomedical visual subject",
        "semantic relationship",
        "composition",
        "style:",
        "voiceover-driven image brief",
        "voiceover-driven keyword image brief",
        "paired voiceover",
        "logic relation",
        "ai image layer prompt",
    ]
    return sum(1 for k in quality_markers if k in lower) < 2

def _force_b_series_3_8s_density(prompts: list[tuple[str, str]], mapping: dict, voiceover_text: str, logger=None):
    """如果外部模型/Gemini 输出的 B 图过少或每图台词过长，则本地重建 B 系列，硬满足 3~8 秒/图。"""
    if not prompts or not str(voiceover_text or "").strip():
        return prompts, mapping

    total = len(prompts)
    b_indices = []
    for i, (name, prompt) in enumerate(prompts, 1):
        page_type = infer_alignment_page_type(name, prompt, i, total)
        if re.search(r"^\s*B\b|Main\s*Content", page_type, flags=re.I) or re.search(r"^B\d+", str(name or ""), flags=re.I):
            b_indices.append(i)

    max_s = max(8.0, float(globals().get("MAX_SECONDS_PER_IMAGE", 8.0) or 8.0))
    # 只有在 B 图明显过少、或某张 B 台词超过 8s 时才接管。
    existing_bad = not b_indices
    for i in b_indices:
        name, prompt = prompts[i - 1]
        if _is_b_prompt_empty_shell(prompt):
            existing_bad = True
            break
        if _estimate_voiceover_seconds_for_visual_segment(mapping.get(i, "")) > max_s * 1.20:
            existing_bad = True
            break

    sentences = ordered_voiceover_sentences_for_alignment(voiceover_text)
    if not sentences:
        return prompts, mapping

    overview_sentence, overview_idx = find_a2_chapter_overview_sentence(voiceover_text)
    closing_sents, closing_idxs = _choose_closing_sentences_for_c(voiceover_text, sentences)
    overview_zero_idx = overview_idx - 1 if overview_idx > 0 else -1

    b_sentences = []
    for i, sent in enumerate(sentences):
        if i == overview_zero_idx:
            continue
        if i in closing_idxs:
            continue
        if sent.strip():
            b_sentences.append(sent.strip())
    timed_segments = _split_sentences_to_3_8s_visual_segments(b_sentences)
    expected_b = len(timed_segments)
    if expected_b <= 0:
        return prompts, mapping
    if len(b_indices) < max(1, int(expected_b * 0.75)):
        existing_bad = True
    if not existing_bad:
        return prompts, mapping

    # 保留 A1/A2/A01/A02 与 C 的槽位/提示词，只重建 B 系列。
    non_b = []
    c_items = []
    for i, item in enumerate(prompts, 1):
        name, prompt = item
        page_type = infer_alignment_page_type(name, prompt, i, total)
        is_b = i in b_indices
        is_c = bool(re.search(r"^\s*C\b|Brand\s*Page|Final", page_type, flags=re.I) or re.search(r"^C\b", str(name or ""), flags=re.I))
        if is_c:
            c_items.append(item)
        elif not is_b:
            non_b.append(item)

    # A 槽保持在前面；如果模型没有给全，使用已有 _force_fixed_page_slots 的结果通常已补齐。
    out = list(non_b[:4]) if non_b else []
    if not out:
        out = list(prompts[:1])
    # 避免把 C 误留在前 4 项里。
    out = [it for it in out if not re.search(r"^\s*C\b|Brand\s*Page|Final", infer_alignment_page_type(it[0], it[1], 0, total), flags=re.I)]

    for idx, seg in enumerate(timed_segments, 1):
        out.append((f"B{idx:02d}", _make_b_prompt_from_voice_segment(seg)))

    def _c_platform(item) -> str:
        name, prompt = item
        joined = f"{name or ''}\n{prompt or ''}"
        if re.search(r"B站|哔哩哔哩|bilibili", joined, flags=re.I):
            return "bilibili"
        if re.search(r"微信|视频号|WeChat", joined, flags=re.I):
            return "wechat"
        return ""

    def _as_platform_c(item, platform: str):
        _name, prompt = item
        if platform == "bilibili":
            return ("C_品牌页_B站", str(prompt or "").rstrip() + "\nPlatform: Bilibili")
        return ("C_品牌页_微信短视频", str(prompt or "").rstrip() + "\nPlatform: WeChat Short Video")

    if not c_items:
        c_text = "\n".join(closing_sents).strip()
        c_prompt = (
            "Page Type: C. Brand Page\n"
            "AI Image Layer Prompt: no-text full-chapter-summary biomedical closing background, visually recap the chapter's established mechanism and bridge only to the next verified question; no text, no logo, no pseudo-text."
        )
        c_items = [
            ("C_品牌页_微信短视频", c_prompt + "\nPlatform: WeChat Short Video"),
            ("C_品牌页_B站", c_prompt + "\nPlatform: Bilibili"),
        ]
    else:
        platforms = {_c_platform(item) for item in c_items}
        base_item = c_items[0]
        normalized_c = []
        if "wechat" in platforms:
            normalized_c.extend(item for item in c_items if _c_platform(item) == "wechat")
        else:
            normalized_c.append(_as_platform_c(base_item, "wechat"))
        if "bilibili" in platforms:
            normalized_c.extend(item for item in c_items if _c_platform(item) == "bilibili")
        else:
            normalized_c.append(_as_platform_c(base_item, "bilibili"))
        c_items = normalized_c
    out.extend(c_items)

    new_mapping = {}
    # A2 绑定章节提要；A1/A01/A02 不承载口播锚点。
    for i, (name, prompt) in enumerate(out, 1):
        page_type = infer_alignment_page_type(name, prompt, i, len(out))
        if re.search(r"\bA2\b|Home\s*Page|首页", page_type + "\n" + name, flags=re.I) and overview_sentence:
            new_mapping[i] = overview_sentence
        elif re.search(r"^\s*B\b|Main\s*Content", page_type, flags=re.I) or re.search(r"^B\d+", str(name or ""), flags=re.I):
            m = re.search(r"^B(\d+)", str(name or ""), flags=re.I)
            bi = int(m.group(1)) if m else 0
            if 1 <= bi <= len(timed_segments):
                new_mapping[i] = timed_segments[bi - 1]
        elif re.search(r"^\s*C\b|Brand\s*Page|Final", page_type, flags=re.I) or re.search(r"^C\b", str(name or ""), flags=re.I):
            new_mapping[i] = "\n".join(closing_sents).strip() or str(mapping.get(i, "")).strip()
        else:
            new_mapping.setdefault(i, "")

    if logger:
        logger(f"🧩 已本地强制重建 B 系列密度：{len(b_indices)} 张 → {len(timed_segments)} 张，按 3~8 秒/图拆分，避免 Gemini 少图或长台词挤一张图。")
    return out, new_mapping



def compose_voice_image_alignment_script(voiceover_text: str, image_prompt_text: str, alignment_text: str, logger=None) -> str:
    """把模型给出的台词映射 + 原始绘图提示词，合成为可拆分的图文一一对应脚本。"""
    global_theme = _summarize_global_script_theme(voiceover_text, limit=260)
    prompts = ScriptParser.extract_image_prompts(image_prompt_text or "", logger=None)
    if not prompts:
        if logger:
            logger("⚠️ 无法生成图文一一对应脚本：没有识别到绘图提示词。")
        return ""
    mapping = parse_voice_image_alignment_map(alignment_text, total_images=len(prompts))
    if not mapping:
        if logger:
            logger("⚠️ 图文对应模型没有返回可解析映射，将回退到旧拆分方式。")
        return ""
    mapping = enforce_a2_chapter_overview_alignment(mapping, voiceover_text, total_images=len(prompts), logger=logger)
    # Gemini/外部模型有时只给少量 B 图，或把几十秒台词塞进一张图；这里先本地兜底强制恢复 3~8 秒/图，
    # 再做补漏，避免先把大量漏句追加到 C 页/最后一图造成误判和日志干扰。
    prompts, mapping = _force_b_series_3_8s_density(prompts, mapping, voiceover_text, logger=logger)
    prompts = _normalize_b_prompt_name_sequence(prompts, logger=logger)
    mapping = _append_missing_voiceover_to_alignment_map(mapping, voiceover_text, logger=logger)
    mapping = enforce_a2_chapter_overview_alignment(mapping, voiceover_text, total_images=len(prompts), logger=None)
    lines = ["====================", "【图文一一对应脚本】", "说明：这是图文台词一一对应的总脚本。每个 Shot 的 Voiceover 是该图对应台词段；Prompt 为对应绘图提示词。配图和文案必须高度相关：Prompt 会附带该图对应台词的语义锁，后续必须先按此总脚本拆分，再单独润色台词。", ""]
    if logger:
        b_prompt_count = sum(1 for idx,(nm,pr) in enumerate(prompts,1) if re.search(r"^B\d+", str(nm or ""), flags=re.I) or re.search(r"^\s*B\b|Main\s*Content", infer_alignment_page_type(nm, pr, idx, len(prompts)), flags=re.I))
        b_voice_count = sum(1 for idx in range(1, len(prompts)+1) if str(mapping.get(idx, "")).strip() and (re.search(r"^B\d+", str(prompts[idx-1][0] or ""), flags=re.I) or re.search(r"^\s*B\b|Main\s*Content", infer_alignment_page_type(prompts[idx-1][0], prompts[idx-1][1], idx, len(prompts)), flags=re.I)))
        logger(f"🔎 B 系列一致性检查：图片 {b_prompt_count} 张，已绑定台词 {b_voice_count} 张。")
    total_images = len(prompts)
    for i, (name, prompt) in enumerate(prompts, 1):
        voice = str(mapping.get(i, "")).strip()
        page_type = infer_alignment_page_type(name, prompt, i, total_images)
        lines.append(f"Shot_{i:02d}:")
        lines.append(f"Source Prompt Name: {name}")
        lines.append(f"Page Type: {page_type}")
        if i == 2:
            lines.append("Alignment Note: A2 Home Page is locked to the chapter overview / 章节提要 sentence, usually voiceover line 003.")
        lines.append("Voiceover:")
        lines.append(voice if voice else "无对应台词")
        lines.append("Prompt:")
        prompt_base = str(prompt or "").strip()
        is_b_page = bool(re.search(r"^\s*B\b|Main\s*Content", page_type, flags=re.I) or re.search(r"^B\d+", str(name or ""), flags=re.I))
        if is_b_page and _is_b_prompt_empty_shell(prompt_base) and voice:
            prompt_base = _make_b_prompt_from_voice_segment(voice)
            if logger:
                logger(f"🩹 已重建空壳 B 提示词：{name}，原提示词只有 Page Type 或缺少可绘制主体。")
        if global_theme and re.search(r"A1|A2|Cover|Home|Brand|Ending|Final|封面|首页|品牌|结尾", page_type, flags=re.I):
            if "GLOBAL SCRIPT THEME / 全章主题锚点" not in prompt_base:
                prompt_base = f"GLOBAL SCRIPT THEME / 全章主题锚点：{global_theme}\n" + prompt_base
        aligned_prompt = _append_visual_copy_relevance_lock(prompt_base, voice, page_type)
        aligned_prompt = _limit_saved_image_prompt_text(aligned_prompt, name=name)
        lines.append(aligned_prompt)
        lines.append("")
    return "\n".join(lines).rstrip() + "\n"


def _remove_lrc_timestamp_prefix(line: str) -> str:
    """移除 LRC 时间戳，只保留台词正文。"""
    return re.sub(r"^\s*\[\d{1,2}:\d{2}(?:\.\d{1,3})?\]\s*", "", str(line or "")).strip()


def _line_lock_alpha_label(index: int) -> str:
    """把 1-based 行号转成 A/B/C...Z/AA/AB 形式，用于台词润色锁定标记。"""
    try:
        n = int(index)
    except Exception:
        return ""
    if n <= 0:
        return ""
    label = ""
    while n > 0:
        n, rem = divmod(n - 1, 26)
        label = chr(65 + rem) + label
    return label


def _line_lock_alpha_label_to_index(label: str) -> int:
    """把 A/B/C...Z/AA/AB 形式还原为 1-based 行号。"""
    s = re.sub(r"[^A-Za-z]", "", str(label or "")).upper()
    if not s:
        return 0
    n = 0
    for ch in s:
        if not ("A" <= ch <= "Z"):
            return 0
        n = n * 26 + (ord(ch) - 64)
    return n


def _normalize_locked_voiceover_line_text(line: str) -> str:
    """清理逐句锁定润色输出中的字母标记、旧数字编号、时间戳、代码围栏和 Markdown 外壳。"""
    s = _remove_lrc_timestamp_prefix(line)
    s = re.sub(r"^```[a-zA-Z0-9_-]*\s*", "", s).strip()
    s = s.replace("```", "").strip()
    s = re.sub(r"^\s*(?:[-*•]\s*)+", "", s).strip()
    # 新规范：允许模型输出 [A] / A. / A、/ A |；超过 26 行时使用 [AA] / [AB]。
    s = re.sub(r"^\s*\[\s*[A-Za-z]{1,3}\s*\]\s*(?:[.、．)\）:：|\-]\s*)?", "", s).strip()
    s = re.sub(r"^\s*[A-Z]{1,3}\s*(?:[.、．)\）:：|\-]\s*)", "", s).strip()
    # 兼容旧模型输出 [001] / 001. / 001、/ 001 | 等格式，但后续提示词不再主动使用数字序号。
    s = re.sub(r"^\s*\[?\s*0*\d{1,4}\s*\]?\s*(?:[.、．)\）:：|\-]\s*)?", "", s).strip()
    s = re.sub(r"^\s*(?:原句|润色后|台词|Voiceover)\s*[：:]\s*", "", s, flags=re.I).strip()
    s = re.sub(r"^(?:\*\*|__)(.*?)(?:\*\*|__)$", r"\1", s).strip()
    return s


def _locked_source_voiceover_rows(marked_source_text: str) -> list[dict]:
    """把已标配图锚点的纯台词拆成逐句锁定行：每一行就是后续润色必须保留的位置。"""
    rows = []
    for raw in str(marked_source_text or "").replace("\r\n", "\n").replace("\r", "\n").splitlines():
        line = normalize_lrc_markers_in_text(_remove_lrc_timestamp_prefix(raw)).strip()
        if not line:
            continue
        if is_visual_prompt_contamination(line):
            continue
        markers = "".join(f"【{normalize_lrc_marker_label(m)}】" for m in LRC_IMAGE_MARKER_CAPTURE_RE.findall(line) if normalize_lrc_marker_label(m) and normalize_lrc_marker_label(m) != "A1")
        text = strip_lrc_image_markers(line).strip()
        if not text:
            continue
        rows.append({"markers": markers, "text": text})
    return rows


def _format_locked_voiceover_rows_for_prompt(marked_source_text: str) -> str:
    """构造给润色模型看的逐句锁定清单；台词行使用 A/B/C 字母标记，不使用 001/002 数字序号。"""
    rows = _locked_source_voiceover_rows(marked_source_text)
    lines = []
    for i, row in enumerate(rows, 1):
        marker = row.get("markers") or ""
        text = row.get("text") or ""
        label = _line_lock_alpha_label(i)
        lines.append(f"[{label}] {marker}{text}")
    return "\n".join(lines)


def _parse_locked_polished_rows(polished_text: str, expected_count: int) -> list[str] | None:
    """解析模型逐句润色结果；只有数量完全一致时才接受。"""
    if expected_count <= 0:
        return None

    text = str(polished_text or "").replace("\r\n", "\n").replace("\r", "\n")
    text = re.sub(r"```[a-zA-Z0-9_-]*", "", text).replace("```", "")
    numbered: dict[int, str] = {}
    candidates = []

    for raw in text.splitlines():
        line = _remove_lrc_timestamp_prefix(raw).strip()
        if not line:
            continue
        # 忽略常见标题和说明，避免“下一章预告”等标题污染 LRC。
        if re.match(r"^\s*(?:【?逐句润色结果】?|【?润色结果】?|【?输出】?|说明|以下是|下一章预告)\s*[:：]?\s*$", line, flags=re.I):
            continue
        # 优先解析新规范的字母标记：[A] / [B] / [AA]，也兼容 A. / A、。
        m_alpha = re.match(r"^\s*\[\s*([A-Za-z]{1,3})\s*\]\s*(?:[.、．)\）:：|\-]\s*)?(.*)$", line)
        if not m_alpha:
            m_alpha = re.match(r"^\s*([A-Z]{1,3})\s*(?:[.、．)\）:：|\-]\s*)(.*)$", line)
        if m_alpha:
            idx = _line_lock_alpha_label_to_index(m_alpha.group(1))
            body = _normalize_locked_voiceover_line_text(m_alpha.group(2))
            if 1 <= idx <= expected_count and body:
                numbered[idx] = body
                continue

        # 兼容旧数字输出，但新提示词不再要求或展示 [001]/[002]。
        m = re.match(r"^\s*\[?\s*0*(\d{1,4})\s*\]?\s*(?:[.、．)\）:：|\-]\s*)?(.*)$", line)
        if m:
            idx = int(m.group(1))
            body = _normalize_locked_voiceover_line_text(m.group(2))
            if 1 <= idx <= expected_count and body:
                numbered[idx] = body
                continue
        body = _normalize_locked_voiceover_line_text(line)
        if body:
            candidates.append(body)

    if len(numbered) == expected_count and all(i in numbered for i in range(1, expected_count + 1)):
        return [numbered[i] for i in range(1, expected_count + 1)]

    # 兼容模型没有编号但逐行返回的情况。
    if len(candidates) == expected_count:
        return candidates

    return None


def normalize_polished_voiceover_to_source_structure(polished_text: str, marked_source_text: str, logger=None) -> str:
    """润色后强制恢复为“源台词逐句结构”。

    硬规则：
    - 输出行数必须等于润色前行数；
    - 每行顺序不变；
    - 每个 LRC 配图锚点回到润色前同一行；
    - 模型若合并、删减、增写、输出下一章预告或数量不一致，则回退到润色前台词，宁可不润色也不破坏图文对应。
    """
    source_rows = _locked_source_voiceover_rows(marked_source_text)
    if not source_rows:
        return str(polished_text or "")

    parsed = _parse_locked_polished_rows(polished_text, len(source_rows))
    if parsed is None:
        if logger:
            got = len([ln for ln in str(polished_text or "").splitlines() if ln.strip()])
            logger(
                f"⚠️ 润色结果未通过逐句锁定校验：源台词 {len(source_rows)} 行，模型返回约 {got} 行。"
                "已回退为润色前逐句台词，避免图片对应、句子数量和先后顺序出错。"
            )
        return "\n".join((row.get("markers") or "") + (row.get("text") or "") for row in source_rows).strip() + "\n"

    out_lines = []
    for row, body in zip(source_rows, parsed):
        clean = _normalize_locked_voiceover_line_text(body)
        # 不允许模型移动或保留错误配图锚点；配图锚点一律由源行恢复。
        clean = strip_lrc_image_markers(normalize_lrc_markers_in_text(clean)).strip()
        if not clean:
            clean = row.get("text") or ""
        out_lines.append((row.get("markers") or "") + clean)


    normalized = "\n".join(out_lines).strip() + "\n"
    if logger:
        logger(f"✅ 润色结果已通过逐句锁定校验：{len(source_rows)} 行，配图锚点、句数和顺序保持不变。")
    return normalized


def build_line_locked_voiceover_polish_prompt(script_text: str, source_text: str = "", toc_text: str = "", next_theme: str = "") -> str:
    """内置兜底逐句润色提示词：一句进，一句出，不允许改变结构。"""
    locked_rows = _format_locked_voiceover_rows_for_prompt(script_text)
    source_excerpt = truncate_context(source_text or "", 12000)
    return (
        "你现在只做中文口播台词的逐句润色。\n"
        "必须遵守以下硬规则：\n"
        "1. 输入有多少行，输出必须有多少行。\n"
        "2. 每一行只能润色同一字母标记后的这一句，不得合并、拆分、删除、增写。\n"
        "3. 输出字母标记必须从 [A]、[B]、[C] 到最后一行连续保留；不要使用 [001]/[002] 数字序号。\n"
        "4. 内部逐句润色阶段，所有 LRC 配图锚点必须留在原字母标记后的行首，不能删除、改号、移动；A1 封面不需要台词锚点；最终 .lrc 导出时程序会把配图锚点拆成独立一行，不与台词合并。\n"
        "5. 只按科学经典解读润色：术语准确、机制清楚、证据边界明确；只能保守润色，不要改成热血、鸡汤、口号或金句。\n"
        "6. 如果原句已经自然、准确、有节制，就尽量不改；只修病句、口播拗口、重复和机械转折。不得为了‘抓人’而增加情绪强度。\n"
        "7. 不要写‘原文介绍了……’‘本章主要讲了……’‘从某某角度看’这类机械解读句；可改成处境、冲突、选择、代价、判断分歧式表达，但不得新增事实。\n"
        "8. 不要输出标题、解释、总结、下一章预告段、Markdown 加粗或项目符号。\n"
        "9. 不要改动台词的事实含义，不要新增原文没有的信息。\n"
        "10. 下一章信息只可用于校对原本已经存在的下一期提示句，不可新增句子。\n\n"
        "【参考原文摘录】\n"
        f"{source_excerpt}\n\n"
        "【待逐句润色台词】\n"
        f"{locked_rows}\n\n"
        "【输出格式】\n"
        "[A] 润色后的第1句\n"
        "[B] 润色后的第2句\n"
        "[C] 润色后的第3句\n"
        "依此类推，只输出逐句结果；超过 Z 后使用 [AA]、[AB]。"
    )


def restore_lrc_markers_after_polish(polished_text: str, marked_source_text: str, logger=None) -> str:
    """台词润色后强制恢复逐句结构，防止模型删句、合句、错图号或输出下一章资料。"""
    return normalize_polished_voiceover_to_source_structure(polished_text, marked_source_text, logger=logger)


def is_voice_image_alignment_script(text: str) -> bool:
    t = str(text or "")
    return any(marker in t for marker in PAIRED_SCRIPT_MARKERS) and bool(PAIRED_SHOT_HEADER_RE.search(t))


PAIRED_SCRIPT_MARKERS = ("【图文一一对应脚本】", "Source Prompt Name:")
PAIRED_SHOT_HEADER_RE = re.compile(r"(?im)^\s*Shot[_\- ]*0*(\d+)\s*[：:]\s*$")


def _extract_paired_voiceover_and_prompt(block_text: str):
    """从单个 Shot 块中提取 Voiceover 和 Prompt。Prompt 后面的内容整体保留。

    v126：如果模型把“Part Two / Production Asset Plan”等资产计划段混在 Shot 后面，
    这里会先截断，避免第二部分被误当作该 Shot 的 Prompt 或后续 Shot。
    """
    body = str(block_text or "").replace("\r\n", "\n").replace("\r", "\n")
    # 只保留图文一一对应脚本的第一部分，后面的资产计划不参与台词/LRC拆分。
    body = re.split(
        r"(?im)^\s*(?:【\s*)?(?:Part\s*Two|Production\s+Asset\s+Plan|资产计划|生产资产计划|分镜资产计划)\b.*$",
        body,
        maxsplit=1,
    )[0]
    vm = re.search(r"(?im)^\s*(?:Voiceover|口播|台词)\s*[：:]\s*$", body)
    pm = re.search(r"(?im)^\s*(?:Prompt|提示词)\s*[：:]\s*$", body)
    if not pm:
        pm = re.search(r"(?im)^\s*(?:Prompt|提示词)\s*[：:]\s*(.+)$", body)
    voice_text = ""
    prompt_text = ""
    if vm and pm:
        voice_text = body[vm.end():pm.start()].strip()
    elif vm:
        voice_text = body[vm.end():].strip()
    if pm:
        if pm.lastindex:
            prompt_text = (pm.group(1) or "").strip()
            prompt_text += ("\n" + body[pm.end():].strip()) if body[pm.end():].strip() else ""
        else:
            prompt_text = body[pm.end():].strip()
    return voice_text.strip(), prompt_text.strip()


def split_paired_alignment_script_to_voiceover_and_prompts(paired_script_text: str):
    """从“图文一一对应脚本”拆出带【图N】锚点的纯台词和独立绘图提示词。

    v126 关键修复：
    - 只读取【图文一一对应脚本】第一部分；
    - 遇到 Part Two / Production Asset Plan 立即停止；
    - 台词按原 Shot 顺序、原句子数量拆出；
    - 每个 Shot 的第一句写入固定【图N】锚点，后续润色不得移动。
    """
    text = str(paired_script_text or "").replace("\r\n", "\n").replace("\r", "\n")
    # 防止完整脚本里的第二部分资产计划再次出现 Shot_01 / Shot_02，导致图号和 Prompt 错位。
    text = re.split(
        r"(?im)^\s*(?:【\s*)?(?:Part\s*Two|Production\s+Asset\s+Plan|资产计划|生产资产计划|分镜资产计划)\b.*$",
        text,
        maxsplit=1,
    )[0]
    matches = list(PAIRED_SHOT_HEADER_RE.finditer(text))
    if not matches:
        return "", ""
    voice_lines = []
    prompt_blocks = []
    image_no = 0
    for idx, m in enumerate(matches):
        start = m.end()
        end = matches[idx + 1].start() if idx + 1 < len(matches) else len(text)
        body = text[start:end]
        voice, prompt = _extract_paired_voiceover_and_prompt(body)
        if not prompt and not voice:
            continue
        image_no += 1
        # v132：保留并显式写出 A1/A2/C 页型，避免后续独立配图阶段把固定页误判成普通内容图。
        source_name = ""
        page_type = ""
        sn = re.search(r"(?im)^\s*Source\s+Prompt\s+Name\s*[：:]\s*(.+?)\s*$", body)
        if sn:
            source_name = sn.group(1).strip()
        pt = re.search(r"(?im)^\s*Page\s*Type\s*[：:]\s*(.+?)\s*$", body)
        if pt:
            page_type = pt.group(1).strip()
        if not page_type:
            try:
                page_type = infer_alignment_page_type(source_name or f"Shot_{image_no:02d}", prompt, image_no, len(matches))
            except Exception:
                if image_no == 1:
                    page_type = "A1. Video Cover Page"
                elif image_no == 2:
                    page_type = "A2. Home Page"
                elif idx == len(matches) - 1:
                    page_type = "C. Brand Page"
                else:
                    page_type = "B. Main Content Page"
        if source_name:
            prompt_name = source_name
        elif re.search(r"\bA1\b|Video\s*Cover", page_type, flags=re.I) or image_no == 1:
            prompt_name = "A1_封面页"
        elif re.search(r"\bA2\b|Home\s*Page", page_type, flags=re.I) or image_no == 2:
            prompt_name = "A2_首页"
        elif re.search(r"\bC\b|Brand\s*Page|Final|Ending", page_type, flags=re.I) or idx == len(matches) - 1:
            if re.search(r"B站|哔哩哔哩|bilibili", page_type + "\n" + prompt, flags=re.I):
                prompt_name = "C_品牌页_B站"
            else:
                prompt_name = "C_品牌页_微信短视频"
        else:
            prompt_name = f"B{max(1, image_no - 2):02d}"

        is_b_page = bool(re.search(r"^\s*B\b|Main\s*Content", page_type, flags=re.I) or re.search(r"^B\d+", str(prompt_name or ""), flags=re.I))
        if is_b_page and _is_b_prompt_empty_shell(prompt) and voice:
            prompt = _make_b_prompt_from_voice_segment(voice)

        prompt_blocks.append(f"Shot_{image_no:02d}:")
        prompt_blocks.append(f"Source Prompt Name: {prompt_name}")
        prompt_blocks.append(f"Page Type: {page_type}")
        prompt_blocks.append(f"Prompt: {prompt.strip()}")
        prompt_blocks.append("")
        cleaned_voice = []
        for raw in voice.splitlines():
            line = clean_voiceover_line(raw)
            if line:
                cleaned_voice.extend(split_voiceover_preserve_sentences(line))
        cleaned_voice = [
            strip_lrc_image_markers(x).strip()
            for x in cleaned_voice
            if strip_lrc_image_markers(x).strip() and strip_lrc_image_markers(x).strip() not in {"无对应台词", "无"}
        ]
        if cleaned_voice:
            cleaned_voice[0] = prefix_lrc_marker_once(cleaned_voice[0], image_no, total_images=len(matches), page_type=page_type, prompt_name=prompt_name)
            voice_lines.extend(cleaned_voice)
    voice_text = "\n".join(voice_lines).strip() + ("\n" if voice_lines else "")
    prompt_text = "\n".join(prompt_blocks).rstrip() + ("\n" if prompt_blocks else "")
    return voice_text, prompt_text


def strip_lrc_image_markers(text: str) -> str:
    """去掉句首连续 LRC 配图锚点，用于去重和匹配；不改写正文。"""
    return re.sub(r"^(?:\s*" + LRC_IMAGE_MARKER_RE.pattern + r")+\s*", "", str(text or ""), flags=re.I).strip()


def has_lrc_image_marker(text: str) -> bool:
    return bool(LRC_IMAGE_MARKER_RE.search(str(text or "")))


def normalize_text_for_marker_match(text: str) -> str:
    """为原稿口播块和剥离台词做宽松匹配。"""
    t = strip_lrc_image_markers(text)
    t = re.sub(r"\s+", "", t)
    t = re.sub(r"[，,。！？!?；;：:、\"'“”‘’（）()【】\[\]《》<>]", "", t)
    return t


SHOT_BLOCK_HEADER_RE = re.compile(
    r"(?im)^\s*(?:#{1,6}\s*)?(?:\*\*)?\s*(?:"
    r"(?:Shot[_\s\-]*\d+|Final\s+Shot)"
    r"|(?:镜头|推文图|图|画面)\s*[_\- ]*\d+"
    r")\b[^\n]*?(?:\*\*)?\s*[：:]?\s*$"
)


def split_script_into_shot_blocks(raw_script_text: str):
    """在完整原稿中按 Shot/镜头/推文图切块；用于拆分前保存图号与台词的真实对应关系。"""
    text = str(raw_script_text or "").replace("\r\n", "\n").replace("\r", "\n")
    matches = list(SHOT_BLOCK_HEADER_RE.finditer(text))
    blocks = []
    for i, m in enumerate(matches):
        start = m.start()
        end = matches[i + 1].start() if i + 1 < len(matches) else len(text)
        header = m.group(0).strip()
        body = text[m.end():end]

        blocks.append((header, body))
    return blocks


def _extract_field_from_block(block_text: str, field_re: re.Pattern) -> str:
    """从单个镜头块中提取口播字段；遇到视觉/提示词/下个字段立即停止。"""
    lines = str(block_text or "").replace("\r\n", "\n").replace("\r", "\n").splitlines()
    collecting = False
    buf = []
    for raw in lines:
        line = raw.strip()
        if not line:
            if collecting:
                # 口播字段通常是一小段；空行不作为内容。
                continue
            continue
        m = field_re.match(line)
        if m:
            collecting = True
            first = _strip_after_any_prompt_marker(m.group(1).strip())
            if first:
                buf.append(first)
            continue
        if collecting:
            if LRC_STOP_FIELD_RE.match(line) or re.match(r"^\s*(?:[-•*]\s*)?(?:视觉画面|画面说明|画面描述|提示词|Prompt|Image Prompt|Page Type|Purpose|用途|页型)\s*[：:]", line, flags=re.I):
                break
            if SHOT_BLOCK_HEADER_RE.match(line):
                break
            cont = re.sub(r"^[-•*\s]+", "", line).strip()
            cont = _strip_after_any_prompt_marker(cont)
            if cont:
                buf.append(cont)
    text = " ".join(x.strip() for x in buf if x.strip()).strip()
    text = _clean_lrc_voiceover_text(text)
    if text in {"无", "没有", "None", "none", "N/A", "n/a", "无。"}:
        return ""
    return text


def block_has_image_prompt(block_text: str) -> bool:
    """判断镜头块是否包含绘图提示词。"""
    return bool(re.search(r"(?im)^\s*(?:[-•*]\s*)?(?:提示词|绘图提示词|图片提示词|Prompt|Image Prompt)\s*[：:]", str(block_text or "")))


def extract_lrc_marker_segments_before_split(raw_script_text: str):
    """在完整原稿拆成两个脚本前，读取每个含图镜头自己的口播，形成 A2/B/C 锚点；A1 封面不加台词锚点。"""
    segments = []
    image_blocks = [(header, body) for header, body in split_script_into_shot_blocks(raw_script_text) if block_has_image_prompt(body)]
    total_images = len(image_blocks)
    for image_no, (header, body) in enumerate(image_blocks, 1):
        voice = _extract_field_from_block(body, VOICEOVER_LABEL_RE)
        if not voice:
            continue
        sentences = split_voiceover_preserve_sentences(voice)
        if not sentences:
            continue
        clean_sentences = [strip_lrc_image_markers(s) for s in sentences if strip_lrc_image_markers(s)]
        if not clean_sentences:
            continue
        clean_sentences[0] = prefix_lrc_marker_once(clean_sentences[0], image_no, total_images=total_images)
        segments.append({"image_no": image_no, "label": lrc_image_label_for_index(image_no, total_images=total_images), "header": header, "sentences": clean_sentences, "voiceover": "\n".join(clean_sentences)})
    return segments

def build_marked_voiceover_from_interleaved_raw(raw_script_text: str) -> str:
    """如果完整原稿是“每个镜头含口播+提示词”的结构，直接按镜头真实关系生成带【图N】的台词。"""
    segments = extract_lrc_marker_segments_before_split(raw_script_text)
    if not segments:
        return ""
    lines = []
    for seg in segments:
        lines.extend(seg.get("sentences") or [])
    return "\n".join([x.strip() for x in lines if x.strip()]) + ("\n" if lines else "")


def prefix_lrc_marker_once(sentence: str, image_no: int, total_images: int = 0, page_type: str = "", prompt_name: str = "") -> str:
    clean = strip_lrc_image_markers(sentence)
    if not clean:
        return ""
    label = lrc_image_label_for_index(image_no, total_images=total_images, page_type=page_type, prompt_name=prompt_name)
    if not label or label in {"A1", "A01", "A02"}:
        return clean
    return f"【{label}】" + clean


def apply_lrc_markers_by_raw_segments(voiceover_text: str, raw_script_text: str) -> str:
    """把拆分前记录到的真实配图锚点，迁移到剥离后的台词文本。"""
    text = str(voiceover_text or "").strip()
    if not text:
        return ""
    if has_lrc_image_marker(text):
        return text + ("\n" if not text.endswith("\n") else "")

    segments = extract_lrc_marker_segments_before_split(raw_script_text)
    if not segments:
        return text + "\n"

    lines = [ln.strip() for ln in text.splitlines() if ln.strip()]
    used = set()
    for seg in segments:
        image_no = int(seg.get("image_no") or 0)
        raw_sentences = [strip_lrc_image_markers(s) for s in (seg.get("sentences") or [])]
        if not image_no or not raw_sentences:
            continue
        target_norm = normalize_text_for_marker_match(raw_sentences[0])
        if not target_norm:
            continue
        best_idx = None
        # 先精确/包含匹配
        for i, line in enumerate(lines):
            if i in used:
                continue
            line_norm = normalize_text_for_marker_match(line)
            if not line_norm:
                continue
            if target_norm == line_norm or target_norm in line_norm or line_norm in target_norm:
                best_idx = i
                break
        # 再按顺序找第一个未标记行，避免完全失败。
        if best_idx is None:
            for i, line in enumerate(lines):
                if i not in used and not has_lrc_image_marker(line):
                    best_idx = i
                    break
        if best_idx is not None:
            lines[best_idx] = prefix_lrc_marker_once(lines[best_idx], image_no)
            used.add(best_idx)
    return "\n".join(lines) + ("\n" if lines else "")


def split_voiceover_into_paragraph_sentence_groups(section_text: str):
    """两段式输出没有镜头口播时的保守兜底：只用原始纯台词区块的自然段边界。"""
    text = str(section_text or "").replace("\r\n", "\n").replace("\r", "\n").strip()
    if not text:
        return []
    paras = [p.strip() for p in re.split(r"\n\s*\n+", text) if p.strip()]
    groups = []
    for para in paras:
        cleaned_lines = []
        for raw in para.splitlines():
            line = clean_voiceover_line(raw)
            if line:
                cleaned_lines.append(line)
        if not cleaned_lines:
            continue
        sentences = []
        for line in cleaned_lines:
            sentences.extend(split_voiceover_preserve_sentences(line))
        if sentences:
            groups.append(sentences)
    return groups


def count_image_prompts_before_split(image_prompt_text: str) -> int:
    """只统计图片张数，不根据张数强行均分台词。"""
    return count_image_prompts_for_lrc(image_prompt_text)


def apply_lrc_markers_by_voiceover_paragraphs(voiceover_text: str, raw_script_text: str, image_prompt_text: str) -> str:
    """两段式脚本兜底：在拆分前利用原始纯台词区块的自然段首句作为配图锚点。"""
    text = str(voiceover_text or "").strip()
    if not text or has_lrc_image_marker(text):
        return text + ("\n" if text and not text.endswith("\n") else "")
    voice_section, _ = split_raw_script_sections(raw_script_text or "")
    groups = split_voiceover_into_paragraph_sentence_groups(voice_section)
    if not groups:
        return text + "\n"
    image_count = count_image_prompts_before_split(image_prompt_text)
    if image_count <= 0:
        return text + "\n"

    # 只在自然段首句打锚点；如果图片多于自然段，再把剩余图号按自然段顺序压到已有段首，避免按句子均分造成错位。
    paragraph_first_norms = [normalize_text_for_marker_match(g[0]) for g in groups if g]
    lines = [ln.strip() for ln in text.splitlines() if ln.strip()]
    used_positions = []
    for norm in paragraph_first_norms:
        found = None
        for i, line in enumerate(lines):
            if i in used_positions:
                continue
            ln = normalize_text_for_marker_match(line)
            if norm and (norm == ln or norm in ln or ln in norm):
                found = i
                break
        if found is None:
            for i, line in enumerate(lines):
                if i not in used_positions and not has_lrc_image_marker(line):
                    found = i
                    break
        if found is not None:
            used_positions.append(found)

    if not used_positions:
        return text + "\n"

    marker_slots = min(max(0, image_count - 1), len(used_positions))
    for offset in range(marker_slots):
        image_no = offset + 2  # A1 封面不生成台词锚点，从 A2 开始。
        pos = used_positions[offset]
        lines[pos] = prefix_lrc_marker_once(lines[pos], image_no, total_images=image_count)

    # 若图片数大于自然段数，剩余非封面图号追加到最后一个已知段首之前，作为“同一段继续对应后续图”的保守提示。
    if image_count - 1 > marker_slots and used_positions:
        last_pos = used_positions[-1]
        rest = "".join(f"【{lrc_image_label_for_index(n, total_images=image_count)}】" for n in range(marker_slots + 2, image_count + 1) if lrc_image_label_for_index(n, total_images=image_count) != "A1")
        lines[last_pos] = rest + strip_lrc_image_markers(lines[last_pos])

    return "\n".join(lines) + ("\n" if lines else "")


def add_lrc_markers_before_script_split(raw_script_text: str, voiceover_text: str, image_prompt_text: str, logger=None) -> str:
    """总入口：完整原稿还在时先记录图号与台词关系，再把标记写进台词。"""
    if not str(voiceover_text or "").strip():
        return ""
    # 1. 最准确：原稿本身按镜头交错，每个镜头含口播和提示词。
    interleaved = build_marked_voiceover_from_interleaved_raw(raw_script_text)
    if interleaved.strip():
        if logger:
            found = len(LRC_IMAGE_MARKER_RE.findall(interleaved))
            logger(f"🔖 已在完整原稿拆分前记录配图-台词对应关系：{found} 个配图锚点。")
        return interleaved

    # 2. 如果剥离后的台词已含图号，直接保留。
    if has_lrc_image_marker(voiceover_text):
        return str(voiceover_text).strip() + "\n"

    # 3. 尝试把原稿镜头锚点迁移到剥离后的台词。
    migrated = apply_lrc_markers_by_raw_segments(voiceover_text, raw_script_text)
    if has_lrc_image_marker(migrated):
        if logger:
            found = len(LRC_IMAGE_MARKER_RE.findall(migrated))
            logger(f"🔖 已根据完整原稿镜头块迁移 LRC 配图锚点：{found} 个。")
        return migrated

    # 4. 两段式输出没有逐镜头口播时，只能用纯台词自然段边界兜底；不再按句子均分。
    paragraph_marked = apply_lrc_markers_by_voiceover_paragraphs(voiceover_text, raw_script_text, image_prompt_text)
    if has_lrc_image_marker(paragraph_marked):
        if logger:
            found = len(LRC_IMAGE_MARKER_RE.findall(paragraph_marked))
            logger(f"🔖 完整原稿未提供逐镜头口播，已按纯台词自然段记录 LRC 配图锚点：{found} 个。")
        return paragraph_marked

    if logger:
        logger("⚠️ 完整原稿中未找到可可靠记录的配图-台词对应关系；LRC 将只输出台词，不强行均分图号。")
    return str(voiceover_text).strip() + "\n"


def split_initial_script_to_two_small_files(raw_script_text: str, logger=None):
    """完整脚本原稿生成后，只剥离台词和绘图提示词，不做简化。

    优先识别“图文一一对应脚本”：这种中间稿已经由模型完成图文同步，
    程序会按 Shot 顺序把【图N】写入对应台词段首句，再拆出绘图提示词。
    普通双区块脚本只作为兼容兜底。
    """
    if is_voice_image_alignment_script(raw_script_text):
        voiceover_text, image_prompt_text = split_paired_alignment_script_to_voiceover_and_prompts(raw_script_text)
        if voiceover_text.strip() or image_prompt_text.strip():
            if logger:
                found = len(LRC_IMAGE_MARKER_RE.findall(voiceover_text))
                logger(f"🔖 已从图文一一对应脚本拆分并写入 LRC 配图锚点：{found} 个。")
            return voiceover_text, image_prompt_text
    voiceover_text, image_prompt_text = split_raw_script_to_voiceover_and_prompts_no_lrc_markers(raw_script_text, logger=logger)
    voiceover_text = add_lrc_markers_before_script_split(raw_script_text, voiceover_text, image_prompt_text, logger=logger)
    return voiceover_text, image_prompt_text


def optimize_voiceover_text_after_split(voiceover_text: str) -> str:
    """兼容旧入口：不再做本地文案优化，只清除误混入的绘图提示词行。

    用户当前要求是“完整脚本原稿生成后不做任何简化，就进行台词润色”。
    因此这里不调用 optimize_script_text_after_generation，也不压缩台词结构。
    """
    return purge_visual_prompt_contamination_from_voiceover(voiceover_text or "")


def split_final_script_to_voiceover_and_prompts(final_script_text: str, logger=None):
    """兼容旧入口：只剥离完整脚本原稿中的台词与绘图提示词，不做简化。"""
    return split_initial_script_to_two_small_files(final_script_text, logger=logger)


def save_script_and_lrc(script_path: str, script_text: str, logger=None) -> str:
    """兼容旧流程：完整脚本原稿原样保存；只剥离台词和绘图提示词，不做简化。"""
    raw_script_text = str(script_text or "")

    # 1) 完整脚本原稿只在调试模式落盘；默认不再保存大体积同义副本。
    raw_backup_path = os.path.splitext(script_path)[0] + "_完整脚本原稿.txt"
    if save_raw_script_backup_enabled():
        write_text_file(raw_backup_path, raw_script_text)

    # 2) 只做结构剥离：台词用于主脚本/LRC，绘图提示词原样进入独立文件。
    raw_voiceover_text, image_prompt_text = split_initial_script_to_two_small_files(raw_script_text, logger=logger)
    voiceover_path = get_voiceover_text_path(script_path)
    prompt_path = get_image_prompt_text_path(script_path)
    pure_script_text = purge_visual_prompt_contamination_from_voiceover(raw_voiceover_text)
    write_separated_voiceover_files(script_path, pure_script_text)
    write_separated_drawing_files(script_path, image_prompt_text)
    write_text_file(script_path, pure_script_text)
    marker_map_path = write_lrc_image_marker_map(script_path, pure_script_text)
    if logger:
        if save_raw_script_backup_enabled():
            logger(f"🧾 完整脚本原稿已另存：{os.path.basename(raw_backup_path)}")
        else:
            logger("🧹 精简模式：完整脚本原稿不再另存，避免大体积中间副本。")
        if os.path.abspath(voiceover_path) == os.path.abspath(script_path):
            logger(f"✅ 最终台词直接复用主脚本文件：{os.path.basename(script_path)}")
        else:
            logger(f"✅ 已剥离并保存纯台词文件：{os.path.basename(voiceover_path)}")
        logger(f"✅ 已保存唯一绘图脚本文件：{os.path.basename(prompt_path)}")
        if marker_map_path:
            logger(f"🔖 LRC 配图台词对应表已保存：{os.path.basename(marker_map_path)}")

    # 3) 只从剥离出的台词生成 LRC。
    lrc_text = generate_lrc_text(pure_script_text, interval_seconds=LRC_INTERVAL_SECONDS, image_prompt_text=image_prompt_text)
    lrc_path = os.path.splitext(script_path)[0] + ".lrc"
    write_text_file(lrc_path, lrc_text)
    if logger:
        line_count = len([line for line in lrc_text.splitlines() if line.strip()])
        logger(f"✅ 已从纯台词生成 LRC：{os.path.basename(lrc_path)}（{line_count} 行，每句间隔30秒，配图锚点来自完整原稿拆分前记录）")
    return lrc_path


def save_voiceover_prompts_and_lrc(script_path: str, voiceover_text: str, image_prompt_text: str, raw_script_text: str = "", logger=None) -> str:
    """双步骤流程专用保存：完整原稿原样保存；润色步骤只改台词；绘图提示词原样保留。"""
    voiceover_path = get_voiceover_text_path(script_path)
    prompt_path = get_image_prompt_text_path(script_path)
    # 润色模型已经完成台词处理；这里不再做本地简化，只防止视觉提示词污染台词。
    pure_voiceover = purge_visual_prompt_contamination_from_voiceover(voiceover_text or "")
    write_separated_voiceover_files(script_path, pure_voiceover)
    write_separated_drawing_files(script_path, image_prompt_text)
    write_text_file(script_path, pure_voiceover)
    marker_map_path = write_lrc_image_marker_map(script_path, pure_voiceover)
    if raw_script_text and save_raw_script_backup_enabled():
        raw_backup_path = os.path.splitext(script_path)[0] + "_完整脚本原稿.txt"
        write_text_file(raw_backup_path, str(raw_script_text or ""))
        if logger:
            logger(f"🧾 完整脚本原稿已另存：{os.path.basename(raw_backup_path)}")
    elif raw_script_text and logger:
        logger("🧹 精简模式：完整脚本原稿不再另存，避免大体积中间副本。")
    lrc_text = generate_lrc_text(pure_voiceover, interval_seconds=LRC_INTERVAL_SECONDS, image_prompt_text=image_prompt_text)
    lrc_path = os.path.splitext(script_path)[0] + ".lrc"
    write_text_file(lrc_path, lrc_text)
    if logger:
        line_count = len([line for line in lrc_text.splitlines() if line.strip()])
        if os.path.abspath(voiceover_path) == os.path.abspath(script_path):
            logger(f"✅ 已保存润色后最终台词主文件：{os.path.basename(script_path)}")
        else:
            logger(f"✅ 已保存润色后纯台词脚本：{os.path.basename(script_path)} / {os.path.basename(voiceover_path)}")
        logger(f"✅ 已保存唯一绘图脚本文件：{os.path.basename(prompt_path)}")
        if marker_map_path:
            logger(f"🔖 LRC 配图台词对应表已保存：{os.path.basename(marker_map_path)}")
        logger(f"✅ 已从纯台词生成 LRC：{os.path.basename(lrc_path)}（{line_count} 行，每句间隔30秒，配图锚点来自最终台词内嵌标记）")
    return lrc_path
